function buildValidationHelperInput() {
  return $input.all().map((item) => {
    const inputJson = item.json || {};

    const rawAttempts = Number(
      inputJson.maxCompileFixAttempts ?? inputJson.maxAttempts ?? inputJson.max_fix_attempts ?? 50,
    );
    const maxCompileFixAttempts = Number.isFinite(rawAttempts)
      ? Math.max(1, Math.min(50, Math.floor(rawAttempts)))
      : 50;

    return {
      json: {
        ...inputJson,
        compileFixAttempt: Number(inputJson.compileFixAttempt || 0),
        maxCompileFixAttempts,
        requirementsText: String(inputJson.requirementsText || ''),
        requirementsFile: String(inputJson.requirementsFile || 'requirements.txt'),
        openapiText: String(inputJson.openapiText || ''),
        openapiFile: String(inputJson.openapiFile || 'openapi.yaml'),
      },
      binary: item.binary ?? {},
    };
  });
}

return buildValidationHelperInput();

const item = $input.first() ?? { json: {}, binary: {} };
const currentJson = item.json ?? {};
const rawBinary = item.binary ?? {};

function getNodeItemSafe(nodeName) {
  if (typeof $items !== 'function') return null;
  try {
    return ($items(nodeName) || [])[0] || null;
  } catch {
    return null;
  }
}

function cleanJson(source) {
  const json = { ...(source ?? {}) };
  delete json.feedback;
  delete json.Feedback;
  delete json.Approved;
  delete json['Start Again'];
  delete json.reviewMode;
  return json;
}

function cleanBinary(source) {
  return Object.fromEntries(
    Object.entries(source ?? {})
      .filter(([key]) => !/^attachments?(?:_|$)/i.test(String(key)))
      .filter(([key]) => !String(key).endsWith('_firstIteration')),
  );
}

function normalizeFiles(value) {
  const files = Array.isArray(value) ? value : [];
  return files
    .map((entry) => {
      if (typeof entry === 'string') return { path: entry.trim() };
      if (entry && typeof entry === 'object') return { path: String(entry.path ?? '').trim() };
      return { path: '' };
    })
    .filter((entry) => entry.path);
}

const firstNode = getNodeItemSafe('BE - Prepare Information for First Iteration');
const firstJson = cleanJson(firstNode?.json ?? {});
const baseJson = cleanJson(currentJson);
const cleanCurrentBinary = cleanBinary(rawBinary);
const firstFiles = normalizeFiles(firstJson.files).length
  ? normalizeFiles(firstJson.files)
  : normalizeFiles(baseJson.firstIterationFiles);
const reviewerFeedback = [
  currentJson.reviewerFeedback,
  currentJson.feedback,
  currentJson.Feedback,
  baseJson.reviewerFeedback,
].map((value) => String(value ?? '').trim()).find((value) => value.length > 0) || '';

const outputJson = {
  ...baseJson,
  reviewerFeedback,
  reviewMode: '',
  firstIterationFiles: firstFiles,
  firstIterationBackendStructure: String(firstJson.backendStructure ?? baseJson.firstIterationBackendStructure ?? '').trim(),
  firstIterationReviewRevisionNumber: Number(firstJson.revisionNumber ?? baseJson.firstIterationReviewRevisionNumber ?? baseJson.revisionNumber ?? 0) || 0,
  firstIterationReviewZipDownloadUrl: String(firstJson.zipDownloadUrl ?? baseJson.firstIterationReviewZipDownloadUrl ?? baseJson.zipDownloadUrl ?? '').trim(),
  firstIterationReviewZipDownloadToken: String(firstJson.zipDownloadToken ?? baseJson.firstIterationReviewZipDownloadToken ?? baseJson.zipDownloadToken ?? '').trim(),
  firstIterationReviewDownloadLinkHtml: String(firstJson.downloadLinkHtml ?? baseJson.firstIterationReviewDownloadLinkHtml ?? baseJson.downloadLinkHtml ?? '').trim(),
};

return [{
  json: outputJson,
  ...(Object.keys(cleanCurrentBinary).length ? { binary: cleanCurrentBinary } : {}),
}];

const item = $input.first();
const json = item?.json ?? {};
const revisionNumber = Math.max(0, Math.trunc(Number(json.revisionNumber ?? 0) || 0));
const fileCount = Math.max(0, Math.trunc(Number(json.fileCount ?? 0) || 0));
const zipDownloadUrl = String(json.zipDownloadUrl ?? '').trim();
if (!zipDownloadUrl) throw new Error('Review ZIP download URL is missing.');
const zipDownloadToken = String(json.zipDownloadToken ?? '').trim();
if (!zipDownloadToken) throw new Error('Review ZIP download token is missing.');
const downloadLinkHtml = '<p><a href="' + zipDownloadUrl + '" download target="_blank" rel="noopener noreferrer">Download current Backend ZIP</a></p>';
const output = {
  json: { ...json, revisionNumber, fileCount, zipDownloadUrl, zipDownloadToken, downloadLinkHtml },
};
if (item.binary && Object.keys(item.binary).length > 0) {
  output.binary = item.binary;
}
return [output];

const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };
const binary = { ...(item.binary ?? {}) };

const backendZip = binary.backendZip;
if (!backendZip) {
  throw new Error('Missing backendZip binary for review link.');
}

binary.reviewZip = backendZip;

return [{
  json,
  binary,
}];

function beAssembleBackendZipInputs() {
    function getExtension(filePath) {
      const fileName = String(filePath || '').split('/').pop() || '';
      if (fileName === 'pom.xml') return 'xml';
      if (fileName === '.gitignore') return 'gitignore';
      const match = fileName.match(/\.([A-Za-z0-9]+)$/);
      return match ? match[1].toLowerCase() : 'txt';
    }
    function getMimeType(filePath) {
      const ext = getExtension(filePath);
      const mimeByExtension = {
        java: 'text/x-java-source',
        xml: 'application/xml',
        yaml: 'text/yaml',
        yml: 'text/yaml',
        json: 'application/json',
        properties: 'text/plain',
        md: 'text/markdown',
        txt: 'text/plain',
        sql: 'application/sql',
        csv: 'text/csv',
        gitignore: 'text/plain',
      };
      return mimeByExtension[ext] || 'text/plain';
    }
    function isIntentionallyEmptyFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('/.gitkeep') || lower.endsWith('/.keep') || lower.endsWith('/.placeholder');
    }
    function normalizeContent(contentValue) {
      if (typeof contentValue === 'string') {
        return contentValue;
      }
      if (contentValue === null || contentValue === undefined) {
        return '';
      }
      if (typeof contentValue === 'object') {
        return JSON.stringify(contentValue, null, 2);
      }
      return String(contentValue);
    }
    const item = $input.first();
    if (!item) {
      throw new Error('No backend generation state available for ZIP assembly.');
    }
    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];
    if (remainingFiles.length > 0) {
      throw new Error('Cannot assemble backend ZIP while files are still remaining.');
    }
    if (!generatedFiles.length) {
      throw new Error('No generated backend files available to assemble ZIP.');
    }
    const binary = {};
    const manifest = [];
    generatedFiles.forEach((file, index) => {
      const filePath = String(file?.path || '').trim();
      const content = normalizeContent(file?.content);
      if (!filePath.startsWith('backend/')) {
        throw new Error(`Generated backend file path must start with "backend/": ${filePath || '<empty>'}`);
      }
      // Empty files are allowed and must still be included in the assembled ZIP.
      const key = `file_${index}`;
      binary[key] = {
        data: Buffer.from(content, 'utf8').toString('base64'),
        mimeType: getMimeType(filePath),
        fileExtension: getExtension(filePath),
        fileName: filePath,
      };
      manifest.push({ path: filePath });
    });
    // Build structure from the actual ZIP payload (single source of truth).
    const zipManifestPaths = Object.values(binary)
      .map((entry) => String(entry?.fileName || '').trim())
      .filter((path) => path.startsWith('backend/'));
    const structureManifest = Array.from(new Set(zipManifestPaths))
      .map((path) => ({ path }))
      .sort((a, b) => a.path.localeCompare(b.path));
    const backendStructureObject = { files: structureManifest };
    const backendStructure = JSON.stringify(backendStructureObject);

    return [{
      json: {
        backendRoot: 'backend',
        fileCount: manifest.length,
        files: manifest,
        backendStructure,
        backendStructureObject,
        zipBinaryFields: Object.keys(binary).join(','),
      },
      binary,
    }];
  }
return beAssembleBackendZipInputs();

function buildValidationHelperOutput() {
  return $input.all().map((item) => ({
    json: {
      validationCompleted: true,
      ...(item.json || {}),
    },
    binary: item.binary ?? {},
  }));
}

return buildValidationHelperOutput();

function beApplyCompileFixes() {
  function normalizePathArray(value) {
    if (!Array.isArray(value)) return [];
    const seen = new Set();
    const normalized = [];
    for (const raw of value) {
      const path = String(raw || '').trim().replace(/\\/g, '/');
      if (!path || !path.startsWith('backend/')) continue;
      if (seen.has(path)) continue;
      seen.add(path);
      normalized.push(path);
    }
    return normalized;
  }

  function normalizeContent(contentValue) {
    if (typeof contentValue === 'string') return contentValue;
    if (contentValue === null || contentValue === undefined) return '';
    if (typeof contentValue === 'object') return JSON.stringify(contentValue, null, 2);
    return String(contentValue);
  }

  function normalizeGeneratedSourceContent(contentValue, filePath) {
    const path = String(filePath || '');
    let text = String(contentValue || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');

    if (/pom\.xml$/i.test(path) || /\.xml$/i.test(path)) {
      const looksEscapedXml =
        /^\s*<\?xml\s+version=\\"/m.test(text)
        || /<[^>\n]+\s+[A-Za-z_:][A-Za-z0-9_.:-]*=\\"/.test(text)
        || (text.includes('\\"') && /<\/?[A-Za-z]/.test(text));

      if (looksEscapedXml) {
        const ESCAPED_QUOTE_SENTINEL = '__N8N_KEEP_ESCAPED_XML_QUOTE__';
        text = text
          .replace(/\\\\\"/g, ESCAPED_QUOTE_SENTINEL)
          .replace(/\\\"/g, '"')
          .replace(new RegExp(ESCAPED_QUOTE_SENTINEL, 'g'), '\\"');
      }

      return text;
    }

    if (!/\.java$/i.test(path)) {
      return text;
    }

    const hasEscapedAnnotationQuotes =
      /@\w+[^\n]*\\\"/.test(text)
      || /\b(name|value|path|strategy)\s*=\s*\\\"/.test(text)
      || /^\s*@RequestMapping\(\\\"/m.test(text);

    if (!hasEscapedAnnotationQuotes) {
      return text;
    }

    const ESCAPED_QUOTE_SENTINEL = '__N8N_KEEP_ESCAPED_QUOTE__';
    text = text.replace(/\\\\\"/g, ESCAPED_QUOTE_SENTINEL);
    text = text.replace(/\\\"/g, '"');
    text = text.replace(new RegExp(ESCAPED_QUOTE_SENTINEL, 'g'), '\\"');
    return text;
  }

  function hasJavaCompileError(errorText) {
    const text = String(errorText || '');
    if (!text) return false;
    return [
      /compilation error/i,
      /cannot find symbol/i,
      /package\s+[A-Za-z0-9_.]+\s+does not exist/i,
      /unknown property/i,
      /incompatible types\s*:/i,
      /illegal character/i,
      /backend[\\/].*src[\\/](main|test)[\\/].*\.(java|kt|groovy)/i,
    ].some((pattern) => pattern.test(text));
  }

  function hasCustomRepositoryOutage(errorText) {
    const text = String(errorText || '').toLowerCase();
    if (!text) return false;
    return (
      text.includes('repo.zalando')
      || text.includes('zalando (https://repo.zalando')
      || text.includes('forbidden (403)')
      || text.includes('name does not resolve')
      || text.includes('repo.spring.io/milestone')
      || text.includes('spring-milestones')
    );
  }

  function isPomChangeRelevant(errorText) {
    const rawText = String(errorText || '');
    const text = rawText.toLowerCase();
    if (!text) return false;

    const explicitPomOrResolutionMarkers = [
      'pom.xml',
      'non-parseable pom',
      'modelparseexception',
      'projectbuildingexception',
      'non-resolvable parent pom',
      'dependencies.dependency.version',
      'could not resolve dependencies',
      'could not collect dependencies',
      'could not resolve artifact',
      'failed to read artifact descriptor',
      'could not transfer artifact',
      'pluginresolutionexception',
      'name does not resolve',
      'forbidden (403)',
    ];

    if (explicitPomOrResolutionMarkers.some((marker) => text.includes(marker))) {
      return true;
    }

    const missingPackages = Array.from(
      rawText.matchAll(/package\s+([A-Za-z0-9_.]+)\s+does not exist/gi),
      (match) => String(match[1] || '').toLowerCase(),
    );

    const hasExternalMissingPackage = missingPackages.some((pkg) => {
      if (!pkg) return false;
      if (pkg.startsWith('com.example.')) return false;
      return /^(org|io|com|net|jakarta|javax)\./.test(pkg);
    });
    if (hasExternalMissingPackage) return true;

    const missingClassFiles = Array.from(
      rawText.matchAll(/class file for\s+([A-Za-z0-9_.]+)\s+not found/gi),
      (match) => String(match[1] || '').toLowerCase(),
    );

    return missingClassFiles.some((className) => {
      if (!className) return false;
      if (className.startsWith('com.example.')) return false;
      return /^(org|io|com|net|jakarta|javax)\./.test(className);
    });
  }

  function analyzePomPolicy(errorText, json) {
    const dependencyOrPomError = isPomChangeRelevant(errorText);
    const javaCompileError = hasJavaCompileError(errorText);
    const customRepoOutage = hasCustomRepositoryOutage(errorText);
    const compileErrorBucket = String(json.compileErrorBucket || '').toLowerCase();
    const errorBucketRepeatCount = Math.max(0, Number(json.errorBucketRepeatCount || 0));
    const mapstructLoopNeedsPom = Boolean(
      compileErrorBucket === 'java-mapstruct-unknown-property'
      && errorBucketRepeatCount >= 2
    );

    const dependencyDrivenPomChange = dependencyOrPomError;
    const allowPom = dependencyDrivenPomChange || mapstructLoopNeedsPom;

    return {
      allowPom,
      javaCompileError,
      customRepoOutage,
      repeatingRepoOutage: customRepoOutage && errorBucketRepeatCount >= 2,
      pomRetryFlood: false,
      mapstructLoopNeedsPom,
    };
  }

  function hasDisallowedPomPatterns(content) {
    const text = String(content || '').toLowerCase();
    if (!text) return false;
    return (
      text.includes('repo.zalando')
      || text.includes('<artifactid>problem-throwable</artifactid>')
    );
  }

  function extractMissingDependencies(errorText) {
    const text = String(errorText || '');
    const found = [];
    const seen = new Set();

    const pattern = /dependency:\s+([A-Za-z0-9_.-]+):([A-Za-z0-9_.-]+):([A-Za-z0-9_.-]+):([A-Za-z0-9_.-]+)/gi;
    for (const match of text.matchAll(pattern)) {
      const groupId = String(match[1] || '').trim();
      const artifactId = String(match[2] || '').trim();
      const version = String(match[4] || '').trim();
      if (!groupId || !artifactId) continue;
      const key = `${groupId}:${artifactId}`;
      if (seen.has(key)) continue;
      seen.add(key);
      found.push({ groupId, artifactId, version });
    }

    return found;
  }

  function extractHistoricalMissingDependencies(history) {
    if (!Array.isArray(history)) return [];
    const merged = [];
    const seen = new Set();
    for (const entry of history.slice(-12)) {
      const text = String(entry?.errorSignature || '');
      for (const dep of extractMissingDependencies(text)) {
        const key = `${dep.groupId}:${dep.artifactId}`;
        if (seen.has(key)) continue;
        seen.add(key);
        merged.push(dep);
      }
    }
    return merged;
  }

  function removeDependencyBlocksByMatcher(pomContent, shouldRemove) {
    let removed = [];
    const next = String(pomContent || '').replace(/<dependency>[\s\S]*?<\/dependency>/gi, (block) => {
      const groupMatch = block.match(/<groupId>\s*([^<\s][^<]*)\s*<\/groupId>/i);
      const artifactMatch = block.match(/<artifactId>\s*([^<\s][^<]*)\s*<\/artifactId>/i);
      const groupId = String(groupMatch?.[1] || '').trim();
      const artifactId = String(artifactMatch?.[1] || '').trim();
      if (!groupId || !artifactId) return block;
      if (!shouldRemove(groupId, artifactId)) return block;
      removed.push(`${groupId}:${artifactId}`);
      return '';
    });

    removed = Array.from(new Set(removed));
    return { content: next, removed };
  }

  function removeBrokenRepositories(pomContent, errorText) {
    let content = String(pomContent || '');
    const removed = [];
    const text = String(errorText || '').toLowerCase();

    const repoPatterns = [
      { key: 'spring-milestones', marker: 'spring.io/milestone', pattern: /<repository>[\s\S]*?<url>\s*https?:\/\/repo\.spring\.io\/milestone\/?\s*<\/url>[\s\S]*?<\/repository>/gi },
      { key: 'repo.zalando', marker: 'repo.zalando', pattern: /<repository>[\s\S]*?<url>\s*https?:\/\/repo\.zalando[^<]*<\/url>[\s\S]*?<\/repository>/gi },
    ];

    for (const cfg of repoPatterns) {
      if (!text.includes(cfg.marker) && !text.includes('could not resolve dependencies')) continue;
      const before = content;
      content = content.replace(cfg.pattern, '');
      if (content !== before) removed.push(cfg.key);
    }

    return { content, removed: Array.from(new Set(removed)) };
  }

  function sanitizePomForDependencyResolution(pomContent, compileErrorContext, compileFixHistory) {
    const currentMissing = extractMissingDependencies(compileErrorContext);
    const historicalMissing = extractHistoricalMissingDependencies(compileFixHistory);

    const missingByGA = new Set();
    const unresolvedArtifactIds = new Set();
    for (const dep of [...historicalMissing, ...currentMissing]) {
      const groupId = String(dep.groupId || '').trim();
      const artifactId = String(dep.artifactId || '').trim();
      if (!groupId || !artifactId) continue;
      missingByGA.add(`${groupId}:${artifactId}`);
      unresolvedArtifactIds.add(artifactId);
    }

    let content = String(pomContent || '');
    const removedDependencies = [];

    const removedExact = removeDependencyBlocksByMatcher(content, (groupId, artifactId) => missingByGA.has(`${groupId}:${artifactId}`));
    content = removedExact.content;
    removedDependencies.push(...removedExact.removed);

    if (unresolvedArtifactIds.size > 0) {
      const removedByArtifact = removeDependencyBlocksByMatcher(content, (_groupId, artifactId) => unresolvedArtifactIds.has(artifactId));
      content = removedByArtifact.content;
      removedDependencies.push(...removedByArtifact.removed);
    }

    const removedRepos = removeBrokenRepositories(content, compileErrorContext);
    content = removedRepos.content;

    return {
      content,
      removedDependencies: Array.from(new Set(removedDependencies)),
      removedRepositories: removedRepos.removed,
      unresolvedArtifacts: Array.from(unresolvedArtifactIds),
    };
  }

  function canCreateNewSourceFile(filePath, compileErrorContext) {
    if (!/\.(java|kt|groovy)$/i.test(String(filePath || ''))) return true;
    const text = String(compileErrorContext || '');
    if (!text) return false;
    const basename = String(filePath || '').split('/').pop() || '';
    const className = basename.replace(/\.(java|kt|groovy)$/i, '');
    if (!className) return false;

    const explicitMissingTypeSignals = [
      /cannot find symbol/i,
      /class file for\s+[A-Za-z0-9_.]+\s+not found/i,
      /should be declared in file/i,
      /package\s+[A-Za-z0-9_.]+\s+does not exist/i,
    ];
    if (!explicitMissingTypeSignals.some((pattern) => pattern.test(text))) return false;
    return text.toLowerCase().includes(className.toLowerCase());
  }

  function buildSingleHunkDiff(path, beforeText, afterText) {
    const beforeLines = String(beforeText || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
    const afterLines = String(afterText || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');

    let prefix = 0;
    while (
      prefix < beforeLines.length
      && prefix < afterLines.length
      && beforeLines[prefix] === afterLines[prefix]
    ) {
      prefix += 1;
    }

    let suffix = 0;
    while (
      suffix < (beforeLines.length - prefix)
      && suffix < (afterLines.length - prefix)
      && beforeLines[beforeLines.length - 1 - suffix] === afterLines[afterLines.length - 1 - suffix]
    ) {
      suffix += 1;
    }

    const beforeChanged = beforeLines.slice(prefix, beforeLines.length - suffix);
    const afterChanged = afterLines.slice(prefix, afterLines.length - suffix);

    const header = [
      `--- ${path}`,
      `+++ ${path}`,
      `@@ -${prefix + 1},${Math.max(1, beforeChanged.length)} +${prefix + 1},${Math.max(1, afterChanged.length)} @@`,
    ];

    const removed = beforeChanged.map((line) => `-${line}`);
    const added = afterChanged.map((line) => `+${line}`);
    return [...header, ...removed, ...added].join('\n');
  }

  function buildPatchPreview(records) {
    const MAX_FILES = 5;
    const MAX_CHARS = 16000;
    const chunks = [];
    let totalChars = 0;
    for (const record of records.slice(0, MAX_FILES)) {
      const diffText = buildSingleHunkDiff(record.path, record.beforeContent, record.afterContent);
      if (!diffText) continue;
      if (totalChars + diffText.length > MAX_CHARS) break;
      chunks.push(diffText);
      totalChars += diffText.length + 2;
    }
    return chunks.join('\n\n');
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const compileFixFiles = Array.isArray(json.compileFixFiles) ? json.compileFixFiles : [];
    const compileFixAllowedPaths = normalizePathArray(json.compileFixAllowedPaths);
    const duplicateClassCandidateFiles = normalizePathArray(json.duplicateClassCandidateFiles);
    const hasDuplicateClassError = Boolean(json.hasDuplicateClassError) || duplicateClassCandidateFiles.length > 0;
    const duplicateClassCandidateSet = new Set(duplicateClassCandidateFiles);
    const compileErrorContext = String(json.compileErrorContext || '');
    const compileErrorBucket = String(json.compileErrorBucket || '').toLowerCase();
    const compileFixHistory = Array.isArray(json.compileFixHistory) ? json.compileFixHistory : [];
    const compileFixUseSurgicalMode = Boolean(json.compileFixUseSurgicalMode);
    const compileFixUseWideRecoveryMode = Boolean(json.compileFixUseWideRecoveryMode);

    const pomPolicy = analyzePomPolicy(compileErrorContext, json);
    const pomChangeAllowed = pomPolicy.allowPom;
    const allowedScopeSet = new Set(compileFixAllowedPaths);

    const byPath = new Map();
    for (const file of generatedFiles) {
      const filePath = String(file?.path || '').trim();
      if (!filePath) continue;
      byPath.set(filePath, normalizeContent(file?.content));
    }

    const changedPaths = [];
    const changedDuplicateCandidatePaths = [];
    const ignoredPomFixPaths = [];
    const ignoredPomFixReasons = [];
    const ignoredScopeFixPaths = [];
    const ignoredScopeFixReasons = [];
    const autoRemovedUnresolvedDependencies = [];
    const autoRemovedRepositoryEntries = [];
    const changedRecords = [];
    let pomSanitizerTouched = false;

    const compileFixIsStuck = Boolean(json.compileFixIsStuck);
    const maxPatchFilesPerAttempt = hasDuplicateClassError
      ? 5
      : (compileFixUseWideRecoveryMode ? 10 : (compileFixUseSurgicalMode ? 3 : (compileFixIsStuck ? 4 : 5)));
    let acceptedPatchFileCount = 0;

    for (const patchFile of compileFixFiles) {
      const filePath = String(patchFile?.path || '').replace(/\\/g, '/').trim();
      if (!filePath) continue;
      if (!filePath.startsWith('backend/')) {
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_outside_backend');
        continue;
      }
      if (allowedScopeSet.size > 0 && !allowedScopeSet.has(filePath)) {
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_outside_allowed_scope');
        continue;
      }
      if (acceptedPatchFileCount >= maxPatchFilesPerAttempt) {
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_patch_limit');
        continue;
      }

      const fileExists = byPath.has(filePath);
      if (!fileExists && !canCreateNewSourceFile(filePath, compileErrorContext)) {
        ignoredScopeFixPaths.push(filePath);
        ignoredScopeFixReasons.push('blocked_new_source_file_without_explicit_missing_type_error');
        continue;
      }

      let nextContent = normalizeContent(patchFile?.content);
      nextContent = normalizeGeneratedSourceContent(nextContent, filePath);

      if (filePath === 'backend/pom.xml') {
        if (!pomChangeAllowed) {
          ignoredPomFixPaths.push(filePath);
          ignoredPomFixReasons.push(
            (pomPolicy.javaCompileError && !pomPolicy.mapstructLoopNeedsPom)
              ? 'blocked_pom_change_due_to_java_compile_error'
              : 'blocked_pom_change_policy'
          );
          continue;
        }

        const shouldSanitizePom = compileErrorBucket === 'dependency-resolution' || compileErrorBucket.startsWith('dependency-');
        if (shouldSanitizePom) {
          const sanitized = sanitizePomForDependencyResolution(nextContent, compileErrorContext, compileFixHistory);
          nextContent = sanitized.content;
          if (sanitized.removedDependencies.length > 0 || sanitized.removedRepositories.length > 0) {
            pomSanitizerTouched = true;
          }
          autoRemovedUnresolvedDependencies.push(...sanitized.removedDependencies);
          autoRemovedRepositoryEntries.push(...sanitized.removedRepositories);
        }

        if (pomPolicy.customRepoOutage && hasDisallowedPomPatterns(nextContent)) {
          ignoredPomFixPaths.push(filePath);
          ignoredPomFixReasons.push(
            pomPolicy.repeatingRepoOutage
              ? 'blocked_pom_change_due_to_repeating_repo_outage'
              : 'blocked_pom_change_due_to_disallowed_repo_or_dependency'
          );
          continue;
        }
      }

      const previousContent = byPath.has(filePath) ? byPath.get(filePath) : null;
      if (previousContent !== nextContent) {
        changedPaths.push(filePath);
        changedRecords.push({
          path: filePath,
          beforeContent: previousContent == null ? '' : String(previousContent),
          afterContent: String(nextContent),
        });
        if (duplicateClassCandidateSet.has(filePath)) {
          changedDuplicateCandidatePaths.push(filePath);
        }
      }
      byPath.set(filePath, nextContent);
      acceptedPatchFileCount += 1;
    }

    const duplicateClassFixRejected = hasDuplicateClassError
      && duplicateClassCandidateSet.size > 0
      && changedDuplicateCandidatePaths.length === 0;

    const mergedGeneratedFiles = Array.from(byPath.entries()).map(([path, content]) => ({ path, content }));
    const mergedPlannedFiles = mergedGeneratedFiles.map((file) => ({ path: file.path }));
    const compileFixNoChangeCount = changedPaths.length
      ? 0
      : Number(json.compileFixNoChangeCount || 0) + 1;
    const compileFixLastPatchPreview = changedRecords.length ? buildPatchPreview(changedRecords) : '';

    return {
      json: {
        ...json,
        generatedFiles: mergedGeneratedFiles,
        generatedFilePaths: mergedGeneratedFiles.map((file) => file.path),
        generatedFileCountTotal: mergedGeneratedFiles.length,
        allPlannedFiles: mergedPlannedFiles,
        compileFixAppliedPaths: changedPaths,
        compileFixAppliedPathCount: changedPaths.length,
        ignoredPomFixPaths,
        ignoredPomFixCount: ignoredPomFixPaths.length,
        ignoredPomFixReasons,
        ignoredScopeFixPaths,
        ignoredScopeFixCount: ignoredScopeFixPaths.length,
        ignoredScopeFixReasons,
        duplicateClassCandidateFiles,
        hasDuplicateClassError,
        changedDuplicateCandidatePaths,
        duplicateClassFixRejected,
        duplicateClassFixRejectedReason: duplicateClassFixRejected
          ? 'no_duplicate_candidate_file_changed'
          : '',
        pomChangeAllowed,
        pomSanitizerTouched,
        autoRemovedUnresolvedDependencies: Array.from(new Set(autoRemovedUnresolvedDependencies)),
        autoRemovedUnresolvedDependencyCount: Array.from(new Set(autoRemovedUnresolvedDependencies)).length,
        autoRemovedRepositoryEntries: Array.from(new Set(autoRemovedRepositoryEntries)),
        autoRemovedRepositoryEntryCount: Array.from(new Set(autoRemovedRepositoryEntries)).length,
        mapstructLoopNeedsPom: pomPolicy.mapstructLoopNeedsPom,
        compileFixIsStuck,
        compileFixUseSurgicalMode,
        compileFixUseWideRecoveryMode,
        maxPatchFilesPerAttempt,
        acceptedPatchFileCount,
        compileFixNoChangeCount,
        compileFixLastPatchPreview,
        compileFixLastPatchChangedFiles: changedRecords.map((entry) => entry.path),
      },
      binary: item.binary ?? {},
    };
  });
}

return beApplyCompileFixes();

function beCleanCompileFixResponse() {
  function getNodeItemsSafe(nodeName) {
    if (typeof $items !== 'function') return [];
    try {
      return $items(nodeName) || [];
    } catch (error) {
      const message = String(error?.message ?? error ?? '');
      if (message.includes("hasn't been executed") || message.includes('not executed')) {
        return [];
      }
      throw error;
    }
  }

  function parseJsonPayload(rawText) {
    const text = String(rawText ?? '').trim();
    if (!text) {
      return { files: [], parseError: 'Empty model response.' };
    }

    function decodeJsonString(value) {
      const raw = String(value || '');
      if (!raw) return '';

      // Decode JSON escape sequences like \n, \", \\ and \uXXXX.
      try {
        return JSON.parse('"' + raw.replace(/"/g, '\\"').replace(/\r/g, '\\r').replace(/\n/g, '\\n') + '"');
      } catch {
        return raw;
      }
    }

    function extractFilesFromMalformedPayload(sourceText) {
      const files = [];
      const seen = new Set();
      const pairRegex = /"path"\s*:\s*"((?:\\.|[^"\\])*)"\s*,\s*"content"\s*:\s*"((?:\\.|[^"\\])*)"/g;
      const reversePairRegex = /"content"\s*:\s*"((?:\\.|[^"\\])*)"\s*,\s*"path"\s*:\s*"((?:\\.|[^"\\])*)"/g;

      for (const match of sourceText.matchAll(pairRegex)) {
        const path = decodeJsonString(match[1]).trim();
        const content = decodeJsonString(match[2]);
        if (!path || seen.has(path)) continue;
        seen.add(path);
        files.push({ path, content });
      }

      for (const match of sourceText.matchAll(reversePairRegex)) {
        const content = decodeJsonString(match[1]);
        const path = decodeJsonString(match[2]).trim();
        if (!path || seen.has(path)) continue;
        seen.add(path);
        files.push({ path, content });
      }

      return files;
    }

    const candidates = [text];
    const tick3 = String.fromCharCode(96, 96, 96);
    const fenceSafeText = text.replace(new RegExp(tick3, 'g'), '~~~');
    const fencedPattern = /~~~(?:json)?\s*([\s\S]*?)\s*~~~/gi;
    for (const match of fenceSafeText.matchAll(fencedPattern)) {
      const candidate = String(match[1] || '').trim();
      if (candidate) candidates.push(candidate);
    }

    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start !== -1 && end !== -1 && end > start) {
      candidates.push(text.slice(start, end + 1));
    }

    const parsedFiles = [];
    for (const candidate of candidates) {
      try {
        const parsed = JSON.parse(candidate);
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
          const files = Array.isArray(parsed.files) ? parsed.files : [];
          for (const file of files) {
            parsedFiles.push(file);
          }
        }
      } catch {}
    }

    if (parsedFiles.length) {
      return { files: parsedFiles, parseError: '' };
    }

    const recoveredFiles = extractFilesFromMalformedPayload(text);
    if (recoveredFiles.length) {
      return { files: recoveredFiles, parseError: '' };
    }

    const lower = text.toLowerCase();
    if (lower.includes('no changes') || lower.includes('cannot fix') || lower.includes('not enough context')) {
      return { files: [], parseError: '' };
    }

    return { files: [], parseError: 'Could not parse compile-fix model output as JSON.' };
  }

  function decodeEscapedContent(rawValue) {
    const text = String(rawValue || '');

    // Keep Java escaping intact (e.g. \" inside string literals).
    // Only decode line breaks if the payload appears fully escaped.
    if (!text.includes('\n') && /\\n|\\r/.test(text)) {
      return text
        .replace(/\\r\\n/g, '\n')
        .replace(/\\n/g, '\n')
        .replace(/\\r/g, '\n')
        .replace(/\\t/g, '\t');
    }

    return text
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n');
  }

  function normalizeGeneratedContent(contentValue) {
    if (typeof contentValue === 'string') return decodeEscapedContent(contentValue);
    if (contentValue === null || contentValue === undefined) return '';
    if (typeof contentValue === 'object') return JSON.stringify(contentValue, null, 2);
    return String(contentValue);
  }

  function compactText(value, maxChars) {
    const text = String(value ?? '');
    if (!text) return '';
    if (text.length <= maxChars) return text;
    return text.slice(0, maxChars);
  }

  const buildPromptItems = getNodeItemsSafe('BE - Build Validation Fix Prompt');

  return $input.all().map((item) => {
    const upstreamJson = buildPromptItems[0]?.json || {};
    const json = {
      ...upstreamJson,
      ...(item.json || {}),
    };
    const rawModelResponse = String(json.text ?? '');
    const parsed = parseJsonPayload(rawModelResponse);
    const allPlannedFiles = Array.isArray(json.allPlannedFiles) ? json.allPlannedFiles : [];

    const compileFixByPath = new Map();
    const ignoredCompileFixPaths = [];

    for (const file of parsed.files) {
      if (!file || typeof file !== 'object' || Array.isArray(file)) continue;
      const filePath = String(file.path || '').replace(/\\/g, '/').trim();
      if (!filePath.startsWith('backend/')) {
        ignoredCompileFixPaths.push(filePath || '<empty>');
        continue;
      }
      if (compileFixByPath.has(filePath)) {
        compileFixByPath.delete(filePath);
      }
      compileFixByPath.set(filePath, normalizeGeneratedContent(file.content));
    }

    const compileFixFiles = Array.from(
      compileFixByPath.entries(),
      ([path, content]) => ({ path, content }),
    );
    const compileFixParsedPaths = compileFixFiles.map((file) => file.path);

    return {
      json: {
        ...json,
        compileFixParseError: parsed.parseError || '',
        compileFixRawResponse: compactText(rawModelResponse, 50000),
        compileFixRawResponseLength: rawModelResponse.length,
        compileFixFiles,
        compileFixParsedPaths,
        compileFixFileCount: compileFixFiles.length,
        compileFixHadChanges: compileFixFiles.length > 0,
        ignoredCompileFixPaths,
        ignoredCompileFixPathCount: ignoredCompileFixPaths.length,
      },
      binary: item.binary ?? {},
    };
  });
}

return beCleanCompileFixResponse();

function beBuildCompileFixPrompt() {
  const MAX_CONTEXT_FILES = 20;
  const MAX_CONTEXT_FILES_DUPLICATE = 30;
  const MAX_CONTEXT_FILES_WIDE = 32;
  const MAX_TOTAL_CONTEXT_CHARS = 90000;
  const MAX_FILE_CONTEXT_CHARS = 14000;
  const MAX_EDIT_SCOPE_GENERAL = 5;
  const MAX_EDIT_SCOPE_SURGICAL = 3;
  const MAX_EDIT_SCOPE_WIDE = 10;

  function normalizePath(value) {
    const raw = String(value || '').trim().replace(/\\/g, '/');
    if (!raw) return '';
    if (raw.startsWith('backend/')) return raw;

    const idx = raw.indexOf('backend/');
    if (idx >= 0) {
      return raw.slice(idx);
    }

    return raw;
  }

  function compactJson(value) {
    return JSON.stringify(value);
  }

  function compactText(value, maxChars) {
    const text = String(value ?? '');
    if (!text) return '';
    return text.length > maxChars ? text.slice(0, maxChars) : text;
  }

  function splitTokens(value) {
    const text = String(value || '')
      .replace(/([a-z0-9])([A-Z])/g, '$1 $2')
      .replace(/[^A-Za-z0-9]+/g, ' ')
      .toLowerCase();
    return Array.from(new Set(text.split(/\s+/).filter((token) => token.length > 1)));
  }

  function normalizeContent(contentValue) {
    if (typeof contentValue === 'string') return contentValue;
    if (contentValue === null || contentValue === undefined) return '';
    if (typeof contentValue === 'object') return JSON.stringify(contentValue, null, 2);
    return String(contentValue);
  }

  function normalizePathArray(value) {
    if (!Array.isArray(value)) return [];
    const seen = new Set();
    const result = [];
    for (const rawPath of value) {
      const path = normalizePath(rawPath);
      if (!path || !path.startsWith('backend/')) continue;
      if (seen.has(path)) continue;
      seen.add(path);
      result.push(path);
    }
    return result;
  }

  function normalizeRecentModelResponses(value) {
    if (!Array.isArray(value)) return [];
    const normalized = [];
    for (const entry of value) {
      if (!entry || typeof entry !== 'object' || Array.isArray(entry)) continue;
      const attempt = Math.max(0, Number(entry.attempt || 0));
      const response = compactText(entry.response, 1800);
      if (!attempt || !response) continue;
      normalized.push({
        attempt,
        parseError: String(entry.parseError || ''),
        parsedPaths: normalizePathArray(entry.parsedPaths).slice(0, 20),
        appliedPaths: normalizePathArray(entry.appliedPaths).slice(0, 20),
        response,
      });
    }
    return normalized.slice(-3);
  }

  function addUniquePath(list, seen, path, pathSet) {
    const normalized = normalizePath(path);
    if (!normalized || !normalized.startsWith('backend/')) return;
    if (!pathSet.has(normalized)) return;
    if (seen.has(normalized)) return;
    seen.add(normalized);
    list.push(normalized);
  }

  function isBuildDependencyError(errorText) {
    const text = String(errorText || '').toLowerCase();
    if (!text) return false;

    return [
      'non-resolvable parent pom',
      'could not resolve dependencies',
      'could not collect dependencies',
      'could not resolve artifact',
      'failed to read artifact descriptor',
      'could not transfer artifact',
      'unable to find valid certification path',
      'dependency resolution',
      'pluginresolutionexception',
      'unknown lifecycle phase',
      'goal requires a project to execute but there is no pom',
      'dependencies.dependency.version',
      'non-parseable pom',
      'modelparseexception',
      'projectbuildingexception',
      'name does not resolve',
      'forbidden (403)',
    ].some((marker) => text.includes(marker));
  }

  function isMapstructError(errorText) {
    const text = String(errorText || '');
    return /mapstruct|unknown property .* in result type|no property named .* exists in source|the type of parameter .* has no property|has no properties\./i.test(text);
  }

  function hasIncompatibleTypeError(errorText) {
    const text = String(errorText || '');
    return /incompatible types\s*:/i.test(text);
  }

  function hasJavaCompileError(errorText) {
    const text = String(errorText || '');
    if (!text) return false;

    return [
      /compilation error/i,
      /cannot find symbol/i,
      /package\s+[A-Za-z0-9_.]+\s+does not exist/i,
      /unknown property/i,
      /incompatible types\s*:/i,
      /illegal character/i,
      /backend[\\/].*src[\\/](main|test)[\\/].*\.(java|kt|groovy)/i,
    ].some((pattern) => pattern.test(text));
  }

  function hasCustomRepositoryOutage(errorText) {
    const text = String(errorText || '').toLowerCase();
    if (!text) return false;
    return (
      text.includes('repo.zalando')
      || text.includes('zalando (https://repo.zalando')
      || text.includes('forbidden (403)')
      || text.includes('name does not resolve')
    );
  }

  function buildGeneratedLookup(generatedFiles) {
    const byPath = new Map();
    const pathSet = new Set();
    const basenameIndex = new Map();

    for (const file of generatedFiles) {
      const path = normalizePath(file?.path);
      if (!path || !path.startsWith('backend/')) continue;

      const content = normalizeContent(file?.content);
      byPath.set(path, content);
      pathSet.add(path);

      const basename = path.split('/').pop()?.toLowerCase() || '';
      if (!basename) continue;
      if (!basenameIndex.has(basename)) basenameIndex.set(basename, []);
      basenameIndex.get(basename).push(path);
    }

    return { byPath, pathSet, basenameIndex };
  }

  function extractReferencedBackendPaths(errorText, generatedPathSet) {
    const text = String(errorText || '');
    const found = new Set();

    const patterns = [
      /backend[\\/][A-Za-z0-9_./\\-]+/g,
      /[A-Za-z]:\\[^\s:]+backend\\[A-Za-z0-9_.\\-]+/g,
      /\/tmp\/[A-Za-z0-9_./-]*backend\/[A-Za-z0-9_./-]+/g,
    ];

    for (const pattern of patterns) {
      for (const match of text.matchAll(pattern)) {
        let value = normalizePath(match[0]);
        value = value.replace(/[),:;\]]+$/, '');
        if (!value.startsWith('backend/')) continue;
        if (!generatedPathSet.has(value)) continue;
        found.add(value);
      }
    }

    return Array.from(found).sort((a, b) => a.localeCompare(b));
  }

  function extractMapstructTypeNames(errorText) {
    const text = String(errorText || '');
    const names = new Set();

    const patterns = [
      /result type\s+"?([A-Za-z_][A-Za-z0-9_$]*)"?/gi,
      /Type\s+"?([A-Za-z_][A-Za-z0-9_$]*)"?\s+has no properties/gi,
      /parameter\s+"?[A-Za-z_][A-Za-z0-9_$]*"?\s+has no property[^\n]*Type\s+"?([A-Za-z_][A-Za-z0-9_$]*)"?/gi,
      /type of parameter\s+"?([A-Za-z_][A-Za-z0-9_$]*)"?\s+has no property/gi,
    ];

    for (const pattern of patterns) {
      for (const match of text.matchAll(pattern)) {
        const className = String(match[1] || '').trim();
        if (!className) continue;
        names.add(className);
      }
    }

    return Array.from(names);
  }

  function resolveClassPaths(classNames, basenameIndex, generatedPathSet) {
    const resolved = new Set();

    for (const className of classNames) {
      const candidates = [
        `${className}.java`,
        `${className}.kt`,
        `${className}.groovy`,
      ];

      for (const candidate of candidates) {
        const options = basenameIndex.get(candidate.toLowerCase()) || [];
        const preferred = options.find((path) => path.includes('/src/main/'))
          || options.find((path) => path.startsWith('backend/'))
          || null;
        if (preferred && generatedPathSet.has(preferred)) {
          resolved.add(preferred);
          break;
        }
      }
    }

    return Array.from(resolved);
  }

  function resolveProjectImportPaths(fileContent, generatedPathSet) {
    const text = String(fileContent || '');
    if (!text) return [];

    const excludedPrefixes = [
      'java.',
      'javax.',
      'jakarta.',
      'lombok.',
      'org.springframework.',
      'org.mapstruct.',
      'org.slf4j.',
      'com.fasterxml.',
      'com.zaxxer.',
      'org.hibernate.',
    ];

    const resolved = new Set();
    const importPattern = /^\s*import\s+([A-Za-z_][A-Za-z0-9_.]*)\s*;/gm;
    for (const match of text.matchAll(importPattern)) {
      const fqn = String(match[1] || '').trim();
      if (!fqn) continue;
      if (excludedPrefixes.some((prefix) => fqn.startsWith(prefix))) continue;
      if (!fqn.includes('.')) continue;

      const mainPath = `backend/src/main/java/${fqn.replace(/\./g, '/')}.java`;
      const testPath = `backend/src/test/java/${fqn.replace(/\./g, '/')}.java`;

      if (generatedPathSet.has(mainPath)) resolved.add(mainPath);
      else if (generatedPathSet.has(testPath)) resolved.add(testPath);
    }

    return Array.from(resolved);
  }

  function isDependencyBucket(bucket) {
    const value = String(bucket || '').toLowerCase();
    if (!value) return false;
    return value.startsWith('dependency-')
      || value.startsWith('pom-')
      || value === 'dependency-resolution';
  }

  function extractMissingSymbolClassNames(errorText) {
    const text = String(errorText || '');
    const names = new Set();
    const patterns = [
      /symbol:\s+class\s+([A-Za-z_][A-Za-z0-9_$]*)/gi,
      /class file for\s+([A-Za-z_][A-Za-z0-9_$.]+)\s+not found/gi,
    ];

    for (const pattern of patterns) {
      for (const match of text.matchAll(pattern)) {
        const raw = String(match[1] || '').trim();
        if (!raw) continue;
        const leaf = raw.includes('.') ? raw.split('.').pop() : raw;
        if (!leaf) continue;
        names.add(leaf);
      }
    }

    return Array.from(names);
  }

  function resolveMissingSymbolPaths(errorText, basenameIndex, generatedPathSet) {
    const resolved = new Set(resolveClassPaths(extractMissingSymbolClassNames(errorText), basenameIndex, generatedPathSet));
    const text = String(errorText || '');
    for (const match of text.matchAll(/package\s+([A-Za-z_][A-Za-z0-9_.]+)\s+does not exist/gi)) {
      const pkg = String(match[1] || '').trim();
      if (!pkg) continue;
      const packagePath = pkg.replace(/\./g, '/');
      const mainPrefix = `backend/src/main/java/${packagePath}/`;
      const testPrefix = `backend/src/test/java/${packagePath}/`;

      for (const candidatePath of generatedPathSet) {
        if (candidatePath.startsWith(mainPrefix) || candidatePath.startsWith(testPrefix)) {
          resolved.add(candidatePath);
        }
      }
    }

    return Array.from(resolved).sort((a, b) => a.localeCompare(b));
  }

  function stripKnownTypeSuffix(typeName) {
    const value = String(typeName || '').trim();
    if (!value) return '';
    return value.replace(/(Resource|Controller|ServiceImpl|Service|Mapper|Repository|DTO|Entity|Model|Request|Response)$/i, '');
  }

  function resolveNearestLayerChainPaths(seedPaths, basenameIndex, generatedPathSet) {
    const exts = ['java', 'kt', 'groovy'];
    const resolved = new Set();
    const roots = new Set();
    const names = new Set();

    for (const path of seedPaths) {
      const normalized = normalizePath(path);
      if (!normalized || !generatedPathSet.has(normalized)) continue;
      const fileName = normalized.split('/').pop() || '';
      const stem = fileName.replace(/\.(java|kt|groovy)$/i, '').trim();
      if (!stem) continue;
      names.add(stem);
      const stripped = stripKnownTypeSuffix(stem);
      if (stripped && stripped.length >= 3) roots.add(stripped);
      if (stem.length >= 3) roots.add(stem);
    }

    for (const root of roots) {
      names.add(root);
      names.add(`${root}Resource`);
      names.add(`${root}Controller`);
      names.add(`${root}Service`);
      names.add(`${root}ServiceImpl`);
      names.add(`${root}Mapper`);
      names.add(`${root}Repository`);
      names.add(`${root}DTO`);
      names.add(`${root}Entity`);
      names.add(`${root}Request`);
      names.add(`${root}Response`);
    }

    for (const name of names) {
      for (const ext of exts) {
        const candidates = basenameIndex.get(`${name}.${ext}`.toLowerCase()) || [];
        for (const candidate of candidates) {
          if (generatedPathSet.has(candidate)) {
            resolved.add(candidate);
          }
        }
      }
    }

    return Array.from(resolved).sort((a, b) => a.localeCompare(b));
  }

  function extractDuplicateClassSimpleNames(errorText) {
    const text = String(errorText || '');
    const names = new Set();

    const patterns = [
      /duplicate class:\s*([A-Za-z_][A-Za-z0-9_$.]*)/gi,
      /duplicate class\s+([A-Za-z_][A-Za-z0-9_$.]*)/gi,
    ];

    for (const pattern of patterns) {
      for (const match of text.matchAll(pattern)) {
        const raw = String(match[1] || '').trim();
        if (!raw) continue;
        const leaf = raw.includes('.') ? raw.split('.').pop() : raw;
        if (!leaf) continue;
        names.add(leaf);
      }
    }

    return Array.from(names);
  }

  function fileDeclaresTopLevelType(fileContent, typeName) {
    const source = String(fileContent || '');
    if (!source || !typeName) return false;

    const escapedName = typeName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const pattern = new RegExp(`^\\s*(?:public\\s+|protected\\s+|private\\s+)?(?:abstract\\s+|final\\s+)?(?:class|interface|enum|record)\\s+${escapedName}\\b`, 'm');
    return pattern.test(source);
  }

  function resolveDuplicateClassPaths(errorText, byPath, pathSet, basenameIndex) {
    const names = extractDuplicateClassSimpleNames(errorText);
    if (!names.length) {
      return { names: [], paths: [] };
    }

    const resolved = new Set(resolveClassPaths(names, basenameIndex, pathSet));
    for (const [path, content] of byPath.entries()) {
      for (const name of names) {
        if (fileDeclaresTopLevelType(content, name)) {
          resolved.add(path);
          break;
        }
      }
    }

    return {
      names,
      paths: Array.from(resolved).sort((a, b) => a.localeCompare(b)),
    };
  }

  function scoreFile(path, options) {
    const {
      errorText,
      relevantPathSet,
      failedTestPathSet,
      testTargetPathSet,
      recentModifiedPathSet,
      shouldPrioritizePom,
    } = options;

    const normalizedPath = normalizePath(path);
    if (!normalizedPath) return 0;

    let score = 0;
    if (relevantPathSet.has(normalizedPath)) score += 120;
    if (failedTestPathSet.has(normalizedPath)) score += 260;
    if (testTargetPathSet.has(normalizedPath)) score += 220;
    if (recentModifiedPathSet.has(normalizedPath)) score += 180;

    if (normalizedPath.endsWith('/pom.xml') || normalizedPath.endsWith('pom.xml')) {
      score += shouldPrioritizePom ? 120 : 0;
    }

    const pathTokens = splitTokens(normalizedPath);
    const errorTokens = splitTokens(errorText).slice(0, 200);
    for (const token of errorTokens) {
      if (pathTokens.includes(token)) score += 2;
    }

    return score;
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const compileValidationStage = String(json.compileValidationStage || 'compile').trim();
    const compileCommand = String(json.compileCommand || '').trim();
    const compileErrorContext = String(json.compileErrorContext || '').trim();
    const compileStdout = String(json.compileStdout || '').trim();
    const compileStderr = String(json.compileStderr || '').trim();
    const compileErrorMessage = String(json.compileErrorMessage || '').trim();
    const errorSignalText = [
      compileErrorContext,
      compactText(compileStdout, 12000),
      compactText(compileStderr, 4000),
      compactText(compileErrorMessage, 2000),
    ].filter(Boolean).join('\n');
    const isRepeatedError = Boolean(json.isRepeatedError);
    const compileErrorBucket = String(json.compileErrorBucket || '').trim();
    const errorBucketRepeatCount = Math.max(0, Number(json.errorBucketRepeatCount || 0));
    const recentPomTouchCount = Math.max(0, Number(json.recentPomTouchCount || 0));
    const compileFixIsStuck = Boolean(json.compileFixIsStuck);
    const compileFixUseSurgicalMode = Boolean(json.compileFixUseSurgicalMode);
    const compileFixUseWideRecoveryMode = Boolean(json.compileFixUseWideRecoveryMode);
    const compileFixWideRecoveryTurnsLeft = Math.max(0, Number(json.compileFixWideRecoveryTurnsLeft || 0));
    const compileFixForceConcreteEdits = Boolean(json.compileFixForceConcreteEdits);
    const compileFixStuckReason = String(json.compileFixStuckReason || '').trim();
    const compileFixRecentModelResponses = normalizeRecentModelResponses(json.compileFixRecentModelResponses);
    const firstCompilerErrors = Array.isArray(json.firstCompilerErrors)
      ? json.firstCompilerErrors.map((line) => String(line || '').trim()).filter(Boolean).slice(0, 20)
      : [];
    const firstCompilerErrorPaths = normalizePathArray(json.firstCompilerErrorPaths);
    const previousAttemptPatchPreview = compactText(json.compileFixLastPatchPreview, 14000);

    const allPlannedFiles = Array.isArray(json.allPlannedFiles) && json.allPlannedFiles.length
      ? json.allPlannedFiles
      : (Array.isArray(json.backendStructure) ? json.backendStructure : []);
    const planPaths = allPlannedFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);

    const relevantErrorPaths = normalizePathArray(json.relevantErrorPaths);
    const testFailedFilePaths = normalizePathArray(json.testFailedFilePaths);
    const testTargetFilePaths = normalizePathArray(json.testTargetFilePaths);
    const compileFixAppliedPaths = normalizePathArray(json.compileFixAppliedPaths);

    const relevantPathSet = new Set(relevantErrorPaths);
    const failedTestPathSet = new Set(testFailedFilePaths);
    const testTargetPathSet = new Set(testTargetFilePaths);
    const recentModifiedPathSet = new Set(compileFixAppliedPaths);

    const { byPath, pathSet, basenameIndex } = buildGeneratedLookup(generatedFiles);
    const hasJavaCompileIssue = hasJavaCompileError(errorSignalText);
    const hasCustomRepoOutage = hasCustomRepositoryOutage(errorSignalText);
    const hasMapstructIssue = isMapstructError(errorSignalText);
    const dependencyBucketStrategy = isDependencyBucket(compileErrorBucket);
    const mapstructBucketStrategy = Boolean(
      hasMapstructIssue || compileErrorBucket === 'java-mapstruct-unknown-property'
    );
    const allowPomForMapstructLoop = Boolean(
      hasMapstructIssue
      && compileErrorBucket === 'java-mapstruct-unknown-property'
      && errorBucketRepeatCount >= 2
    );
    const shouldPrioritizePom = (isBuildDependencyError(errorSignalText) && !hasJavaCompileIssue)
      || allowPomForMapstructLoop;
    const pomTriedTooManyTimes = recentPomTouchCount >= 3;
    const disablePomEditsForThisTurn = Boolean(
      (!allowPomForMapstructLoop && pomTriedTooManyTimes)
      || (errorBucketRepeatCount >= 3 && !shouldPrioritizePom)
      || (!allowPomForMapstructLoop && hasCustomRepoOutage && compileErrorBucket.includes('zalando'))
    );
    const hasIncompatibleTypeIssue = hasIncompatibleTypeError(errorSignalText);
    const requiresMapstructCoordinatedFix = Boolean(
      hasMapstructIssue && (isRepeatedError || Number(json.compileFixAttempt || 0) >= 2)
    );
    const referencedErrorPaths = extractReferencedBackendPaths(errorSignalText, pathSet);
    const missingSymbolCandidatePaths = resolveMissingSymbolPaths(errorSignalText, basenameIndex, pathSet);
    const symbolChainPaths = compileErrorBucket === 'java-cannot-find-symbol'
      ? resolveNearestLayerChainPaths(
        [...firstCompilerErrorPaths, ...referencedErrorPaths, ...missingSymbolCandidatePaths],
        basenameIndex,
        pathSet
      )
      : [];
    const duplicateClassResolution = resolveDuplicateClassPaths(errorSignalText, byPath, pathSet, basenameIndex);
    const duplicateClassNames = duplicateClassResolution.names;
    const duplicateClassCandidatePaths = duplicateClassResolution.paths;
    const hasDuplicateClassError = duplicateClassNames.length > 0;

    const mapstructMapperPaths = [];
    const mapstructClassPaths = [];
    if (hasMapstructIssue) {
      const typeNames = extractMapstructTypeNames(errorSignalText);
      mapstructClassPaths.push(...resolveClassPaths(typeNames, basenameIndex, pathSet));

      const combinedErrorPaths = [...relevantErrorPaths, ...referencedErrorPaths];
      for (const path of combinedErrorPaths) {
        if (/\/mapper\//i.test(path) || /Mapper\.(java|kt|groovy)$/i.test(path)) {
          mapstructMapperPaths.push(path);
        }
      }

      if (!mapstructMapperPaths.length) {
        for (const path of byPath.keys()) {
          if (/\/mapper\/.*Mapper\.(java|kt|groovy)$/i.test(path)) {
            mapstructMapperPaths.push(path);
          }
        }
      }
    }

    const priorityContextPaths = [];
    const seenPriority = new Set();
    const addPriorityPath = (path) => addUniquePath(priorityContextPaths, seenPriority, path, pathSet);

    // 1) Always prioritize duplicate-class candidates first when present.
    for (const path of duplicateClassCandidatePaths) addPriorityPath(path);

    // 2) Always include files referenced by the first compiler errors.
    for (const path of firstCompilerErrorPaths) addPriorityPath(path);

    // 3) Prioritize files directly implicated by current compiler/runtime errors.
    for (const path of referencedErrorPaths) addPriorityPath(path);
    for (const path of relevantErrorPaths) addPriorityPath(path);
    for (const path of missingSymbolCandidatePaths) addPriorityPath(path);
    for (const path of symbolChainPaths) addPriorityPath(path);
    for (const path of compileFixAppliedPaths) addPriorityPath(path);

    // 4) When the loop is stuck, include files from recent model attempts to prevent repetition.
    if (compileFixIsStuck) {
      for (const entry of compileFixRecentModelResponses) {
        for (const path of normalizePathArray(entry.parsedPaths)) addPriorityPath(path);
        for (const path of normalizePathArray(entry.appliedPaths)) addPriorityPath(path);
      }
    }

    // 5) Add test-target context.
    for (const path of testFailedFilePaths) addPriorityPath(path);
    for (const path of testTargetFilePaths) addPriorityPath(path);

    // 6) Add mapper-specific files when relevant.
    for (const path of mapstructMapperPaths) addPriorityPath(path);
    for (const path of mapstructClassPaths) addPriorityPath(path);

    // 7) Add pom context only when allowed and relevant.
    if ((shouldPrioritizePom || hasMapstructIssue) && !disablePomEditsForThisTurn) {
      addPriorityPath('backend/pom.xml');
    }

    // 8) Expand imports from prioritized Java/Kotlin/Groovy files so related DTO/repository
    // contracts are present in context for coordinated type fixes.
    const importExpandedPaths = [];
    const seenImportExpanded = new Set();
    for (const path of priorityContextPaths) {
      if (!/\.(java|kt|groovy)$/i.test(path)) continue;
      const sourceContent = byPath.get(path);
      if (!sourceContent) continue;
      const importedProjectPaths = resolveProjectImportPaths(sourceContent, pathSet);
      for (const importedPath of importedProjectPaths) {
        addUniquePath(importExpandedPaths, seenImportExpanded, importedPath, pathSet);
      }
    }

    const forcedContextPaths = [];
    const seenForced = new Set();
    for (const path of priorityContextPaths) addUniquePath(forcedContextPaths, seenForced, path, pathSet);
    for (const path of importExpandedPaths) addUniquePath(forcedContextPaths, seenForced, path, pathSet);

    const editableScopePaths = [];
    const seenEditableScope = new Set();
    const addEditableScopePath = (path) => addUniquePath(editableScopePaths, seenEditableScope, path, pathSet);

    if (hasDuplicateClassError) {
      for (const path of duplicateClassCandidatePaths) addEditableScopePath(path);
    } else if (dependencyBucketStrategy) {
      // Keep dependency-resolution scope strictly on pom.xml to avoid irrelevant Java churn.
      if (!disablePomEditsForThisTurn) addEditableScopePath('backend/pom.xml');
      if (!editableScopePaths.length) {
        for (const path of referencedErrorPaths) addEditableScopePath(path);
        for (const path of relevantErrorPaths) addEditableScopePath(path);
      }
    } else if (mapstructBucketStrategy) {
      for (const path of mapstructMapperPaths) addEditableScopePath(path);
      for (const path of mapstructClassPaths) addEditableScopePath(path);
      for (const path of referencedErrorPaths) addEditableScopePath(path);
      for (const path of relevantErrorPaths) addEditableScopePath(path);
      for (const path of importExpandedPaths) addEditableScopePath(path);
      if (allowPomForMapstructLoop && !disablePomEditsForThisTurn) {
        addEditableScopePath('backend/pom.xml');
      }
    } else if (compileErrorBucket === 'java-cannot-find-symbol') {
      for (const path of firstCompilerErrorPaths) addEditableScopePath(path);
      for (const path of missingSymbolCandidatePaths) addEditableScopePath(path);
      for (const path of symbolChainPaths) addEditableScopePath(path);
      for (const path of referencedErrorPaths) addEditableScopePath(path);
      for (const path of relevantErrorPaths) addEditableScopePath(path);
      if (compileFixUseWideRecoveryMode) {
        for (const path of importExpandedPaths) addEditableScopePath(path);
      }
    } else {
      for (const path of firstCompilerErrorPaths) addEditableScopePath(path);
      for (const path of referencedErrorPaths) addEditableScopePath(path);
      for (const path of relevantErrorPaths) addEditableScopePath(path);
      if (compileFixUseWideRecoveryMode) {
        for (const path of importExpandedPaths) addEditableScopePath(path);
      }
    }

    const scopedWithFirstErrorPaths = [];
    const seenScopedWithFirstErrorPaths = new Set();
    const addScopedPath = (path) => {
      const normalized = normalizePath(path);
      if (!normalized || !pathSet.has(normalized)) return;
      if (seenScopedWithFirstErrorPaths.has(normalized)) return;
      seenScopedWithFirstErrorPaths.add(normalized);
      scopedWithFirstErrorPaths.push(normalized);
    };
    if (dependencyBucketStrategy) {
      for (const path of editableScopePaths) addScopedPath(path);
      for (const path of firstCompilerErrorPaths) addScopedPath(path);
    } else {
      for (const path of firstCompilerErrorPaths) addScopedPath(path);
      for (const path of editableScopePaths) addScopedPath(path);
    }

    const maxEditableFiles = compileFixUseWideRecoveryMode
      ? MAX_EDIT_SCOPE_WIDE
      : (compileFixUseSurgicalMode ? MAX_EDIT_SCOPE_SURGICAL : MAX_EDIT_SCOPE_GENERAL);
    let compileFixAllowedPaths = scopedWithFirstErrorPaths.slice(0, maxEditableFiles);
    if (dependencyBucketStrategy && !disablePomEditsForThisTurn && pathSet.has('backend/pom.xml')) {
      if (!compileFixAllowedPaths.includes('backend/pom.xml')) {
        compileFixAllowedPaths = ['backend/pom.xml', ...compileFixAllowedPaths]
          .filter((path, index, arr) => arr.indexOf(path) === index)
          .slice(0, Math.max(1, maxEditableFiles));
      } else {
        compileFixAllowedPaths = ['backend/pom.xml', ...compileFixAllowedPaths.filter((path) => path !== 'backend/pom.xml')]
          .slice(0, Math.max(1, maxEditableFiles));
      }
    }
    const hasScopedEdits = compileFixAllowedPaths.length > 0;

    const candidates = Array.from(byPath.entries())
      .map(([path, content]) => ({
        path,
        content,
        score: scoreFile(path, {
          errorText: errorSignalText,
          relevantPathSet,
          failedTestPathSet,
          testTargetPathSet,
          recentModifiedPathSet,
          shouldPrioritizePom,
        }),
      }))
      .filter((file) => file.score > 0)
      .sort((a, b) => b.score - a.score || a.path.localeCompare(b.path));

    const contextFiles = [];
    const seenContextPaths = new Set();
    const allowedScopeSet = new Set(compileFixAllowedPaths);
    let totalChars = 0;
    const maxContextFiles = hasDuplicateClassError
      ? Math.max(MAX_CONTEXT_FILES_DUPLICATE, duplicateClassCandidatePaths.length + 8)
      : (compileFixUseWideRecoveryMode ? MAX_CONTEXT_FILES_WIDE : MAX_CONTEXT_FILES);

    function addContextPath(path) {
      if (contextFiles.length >= maxContextFiles || totalChars >= MAX_TOTAL_CONTEXT_CHARS) return;
      if (seenContextPaths.has(path)) return;
      if (!byPath.has(path)) return;

      const remaining = MAX_TOTAL_CONTEXT_CHARS - totalChars;
      const take = Math.min(MAX_FILE_CONTEXT_CHARS, remaining);
      const content = String(byPath.get(path) || '').slice(0, take);

      contextFiles.push({ path, content });
      seenContextPaths.add(path);
      totalChars += content.length;
    }

    if (hasDuplicateClassError) {
      for (const path of duplicateClassCandidatePaths) {
        addContextPath(path);
      }
    }

    for (const path of firstCompilerErrorPaths) {
      if (dependencyBucketStrategy && path !== 'backend/pom.xml') continue;
      addContextPath(path);
    }

    if (hasScopedEdits) {
      for (const path of compileFixAllowedPaths) {
        addContextPath(path);
      }
    }

    for (const path of forcedContextPaths) {
      if (hasScopedEdits && !allowedScopeSet.has(path)) continue;
      addContextPath(path);
    }

    for (const file of candidates) {
      if (hasScopedEdits && !allowedScopeSet.has(file.path)) continue;
      addContextPath(file.path);
    }

    const compileFixPromptPayload = {
      command: compileCommand,
      validationStage: compileValidationStage,
      errorLog: errorSignalText,
      firstCompilerErrors,
      previousAttemptPatchPreview,
      contextFiles,
      allowedFilesPlan: planPaths,
      allowedEditScopePaths: compileFixAllowedPaths,
      strategy: {
        mode: compileFixUseWideRecoveryMode ? 'wide-recovery' : (compileFixUseSurgicalMode ? 'surgical' : 'standard'),
        maxFilesToEdit: maxEditableFiles,
        focusHint: compileFixUseWideRecoveryMode
          ? 'Wide recovery: edit related interface/impl/mapper/resource chain files to break stagnation.'
          : (compileFixUseSurgicalMode
          ? 'Edit only files from first compiler errors and stop broad rewrites.'
          : 'Keep changes minimal and focused on directly implicated files.'),
      },
      relevantFiles: {
        firstCompilerErrorFiles: firstCompilerErrorPaths,
        errorReferencedFiles: referencedErrorPaths,
        recentlyModifiedFiles: compileFixAppliedPaths,
        failedTestFiles: testFailedFilePaths,
        testTargetFiles: testTargetFilePaths,
        missingSymbolCandidateFiles: missingSymbolCandidatePaths,
        symbolChainFiles: symbolChainPaths,
        duplicateClassCandidateFiles: duplicateClassCandidatePaths,
      },
      state: {
        attempt: Number(json.compileFixAttempt || 0),
        maxAttempts: Number(json.maxCompileFixAttempts || 50),
        isRepeatedError,
        errorBucket: compileErrorBucket,
        errorBucketRepeatCount,
        hasJavaCompileIssue,
        hasMapstructIssue,
        hasIncompatibleTypeIssue,
        hasDuplicateClassError,
        duplicateClassSimpleNames: duplicateClassNames,
        requiresMapstructCoordinatedFix,
        shouldPrioritizePom,
        allowPomForMapstructLoop,
        disablePomEditsForThisTurn,
        dependencyBucketStrategy,
        mapstructBucketStrategy,
        useSurgicalMode: compileFixUseSurgicalMode,
        useWideRecoveryMode: compileFixUseWideRecoveryMode,
        wideRecoveryTurnsLeft: compileFixWideRecoveryTurnsLeft,
        forceConcreteEdits: compileFixForceConcreteEdits,
        isStuckCycle: compileFixIsStuck,
        stuckReason: compileFixStuckReason,
      },
      recentModelResponses: compileFixIsStuck ? compileFixRecentModelResponses : [],
    };
    const compileFixPrompt = compactJson(compileFixPromptPayload);

    return {
      json: {
        ...json,
        allPlannedFiles,
        compileFixPrompt,
        compileFixPromptLength: compileFixPrompt.length,
        compileFixContextFileCount: contextFiles.length,
        compileFixContextPaths: contextFiles.map((file) => file.path),
        compileFixForcedContextPaths: forcedContextPaths,
        compileFixAllowedPaths,
        duplicateClassCandidateFiles: duplicateClassCandidatePaths,
        hasDuplicateClassError,
        compileFixScopeStrategy: compileFixUseSurgicalMode
          ? 'surgical-first-errors'
          : (compileFixUseWideRecoveryMode
            ? 'wide-recovery'
          : (hasDuplicateClassError
          ? 'duplicate-class-focused'
          : (dependencyBucketStrategy
            ? 'dependency-focused'
            : (mapstructBucketStrategy ? 'mapstruct-focused' : 'general')))),
        compileFixRecentModelResponseCount: compileFixRecentModelResponses.length,
      },
      binary: item.binary ?? {},
    };
  });
}

return beBuildCompileFixPrompt();

function bePrepareCompileFixState() {
  const MAX_RECENT_MODEL_RESPONSES = 3;
  const MAX_FIRST_COMPILER_ERRORS = 20;
  const STAGNATION_WINDOW = 3;
  const WIDE_RECOVERY_BUCKET_THRESHOLD = 4;
  const WIDE_RECOVERY_NO_CHANGE_THRESHOLD = 3;
  const WIDE_RECOVERY_ITERATIONS = 2;

  function toText(value) {
    return String(value ?? '').trim();
  }

  function buildErrorSignature(value) {
    const text = String(value ?? '')
      .toLowerCase()
      .replace(/[a-z]:\\[^\\n\\r\\t ]*backend\\/g, 'backend/')
      .replace(/\/tmp\/n8n-backend-build\/[a-z0-9-]+\/backend\//g, 'backend/')
      .replace(/\[[0-9]+,[0-9]+\]/g, '[n,n]')
      .replace(/:[0-9]+(?=[)\s]|$)/g, ':n')
      .replace(/\s+/g, ' ')
      .trim();

    if (!text) return '';
    return text.length > 5000 ? text.slice(0, 5000) : text;
  }

  function buildErrorBucket(value) {
    const text = String(value ?? '').toLowerCase();
    if (!text) return '';

    if (text.includes('pre_compile_guard_failed')) {
      return 'pre-compile-guard-failed';
    }

    if (text.includes('dependencies.dependency.version') && text.includes('org.testcontainers:redis')) {
      return 'pom-missing-testcontainers-redis-version';
    }

    if (
      text.includes('repo.zalando')
      || text.includes('forbidden (403)')
      || text.includes('name does not resolve')
    ) {
      return 'dependency-zalando-repository-unreachable';
    }

    if (
      text.includes('problem-throwable')
      || text.includes('package org.zalando.problem.throwable does not exist')
    ) {
      return 'java-missing-zalando-problem-throwable';
    }

    if (text.includes('unknown property') && text.includes('/mapper/')) {
      return 'java-mapstruct-unknown-property';
    }

    if (
      text.includes('failed to initialize jpa entitymanagerfactory')
      || (text.includes('table [') && text.includes('contains physical column name'))
    ) {
      return 'spring-boot-jpa-entity-mapping';
    }

    if (
      text.includes('application run failed')
      || text.includes('error starting applicationcontext')
      || text.includes('beancreationexception')
    ) {
      return 'spring-boot-startup-failure';
    }

    if (text.includes('cannot find symbol')) {
      return 'java-cannot-find-symbol';
    }

    if (text.includes('duplicate class')) {
      return 'java-duplicate-class';
    }

    if (text.includes('public type "') && text.includes('must be declared in')) {
      return 'java-duplicate-class';
    }

    if (text.includes('package ') && text.includes(' does not exist')) {
      return 'java-missing-package';
    }

    if (text.includes('compilation error')) {
      return 'java-compilation-error';
    }

    if (text.includes('could not resolve dependencies') || text.includes('failed to read artifact descriptor')) {
      return 'dependency-resolution';
    }

    if (text.includes('non-parseable pom') || text.includes('modelparseexception')) {
      return 'pom-parse-error';
    }

    return text
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 120);
  }

  function normalizePathArray(value) {
    if (!Array.isArray(value)) return [];
    const seen = new Set();
    const normalized = [];
    for (const raw of value) {
      const path = String(raw || '').trim().replace(/\\/g, '/');
      if (!path || !path.startsWith('backend/')) continue;
      if (seen.has(path)) continue;
      seen.add(path);
      normalized.push(path);
    }
    return normalized;
  }

  function pickErrorSummary(parts, maxChars) {
    const text = parts.filter(Boolean).join('\n').trim();
    if (!text) return '';
    return text.length > maxChars ? text.slice(0, maxChars) : text;
  }

  function compactText(value, maxChars) {
    const text = String(value ?? '');
    if (!text) return '';
    return text.length > maxChars ? text.slice(0, maxChars) : text;
  }

  function normalizeRecentModelResponses(value) {
    if (!Array.isArray(value)) return [];
    const normalized = [];
    for (const entry of value) {
      if (!entry || typeof entry !== 'object' || Array.isArray(entry)) continue;
      const attempt = Math.max(0, Number(entry.attempt || 0));
      const response = compactText(entry.response, 2400);
      if (!attempt || !response) continue;
      normalized.push({
        attempt,
        parseError: toText(entry.parseError),
        parsedPaths: normalizePathArray(entry.parsedPaths).slice(0, 20),
        appliedPaths: normalizePathArray(entry.appliedPaths).slice(0, 20),
        response,
      });
    }
    return normalized.slice(-MAX_RECENT_MODEL_RESPONSES);
  }

  function splitLines(value) {
    return String(value ?? '')
      .split(/\r?\n/)
      .map((line) => String(line || '').trim())
      .filter(Boolean);
  }

  function extractCompilerErrorLines(value, maxLines = MAX_FIRST_COMPILER_ERRORS) {
    const lines = splitLines(value);
    const selected = [];
    for (const line of lines) {
      if (!line.startsWith('[ERROR]')) continue;
      const normalized = line.replace(/\s+/g, ' ').trim();
      if (
        normalized === '[ERROR]'
        || normalized.startsWith('[ERROR] -> [Help ')
        || normalized.includes('For more information about the errors and possible solutions')
      ) {
        continue;
      }
      selected.push(normalized);
      if (selected.length >= maxLines) break;
    }
    return selected;
  }

  function countCompilerErrorLines(value) {
    return extractCompilerErrorLines(value, 5000).length;
  }

  function getBucketSeverityScore(bucket, stage) {
    const normalizedBucket = String(bucket || '').toLowerCase();
    const normalizedStage = String(stage || '').toLowerCase();
    let score = 0;

    if (normalizedStage === 'compile') score += 60000;
    else if (normalizedStage === 'guard') score += 50000;
    else if (normalizedStage === 'run') score += 30000;
    else if (normalizedStage === 'test') score += 10000;
    else score += 40000;

    if (!normalizedBucket) return score + 5000;
    if (normalizedBucket.startsWith('pom-') || normalizedBucket.startsWith('dependency-')) return score + 9000;
    if (normalizedBucket === 'dependency-resolution') return score + 8500;
    if (normalizedBucket === 'java-compilation-error') return score + 7000;
    if (normalizedBucket === 'java-duplicate-class') return score + 6800;
    if (normalizedBucket === 'java-mapstruct-unknown-property') return score + 6500;
    if (normalizedBucket === 'java-cannot-find-symbol') return score + 6000;
    if (normalizedBucket === 'java-missing-package') return score + 5800;
    if (normalizedBucket.startsWith('spring-boot-')) return score + 3000;
    return score + 5000;
  }

  function computeConvergenceScore(params) {
    if (params.compilePassed) return 0;
    const bucketScore = getBucketSeverityScore(params.errorBucket, params.validationStage);
    const errorLineScore = Math.min(15000, Math.max(0, params.errorLineCount) * 25);
    const noChangePenalty = Math.min(5000, Math.max(0, params.noChangeCount) * 700);
    return bucketScore + errorLineScore + noChangePenalty + 1;
  }

  function isDependencyLikeBucket(bucket) {
    const value = String(bucket || '').toLowerCase();
    if (!value) return false;
    return value === 'dependency-resolution' || value.startsWith('dependency-') || value.startsWith('pom-');
  }

  function hasNonDecreasingTrend(values) {
    if (!Array.isArray(values) || values.length < STAGNATION_WINDOW) return false;
    for (let index = 1; index < values.length; index += 1) {
      if (values[index] < values[index - 1]) return false;
    }
    return true;
  }

  function isLogbackNoiseLine(line) {
    const text = String(line || '').toLowerCase();
    if (!text) return false;
    if (text.includes('|-info in') && text.includes('logback')) return true;
    if (text.includes('logback.classic') || text.includes('logback.core')) return true;
    if (text.includes('contextinitializer') || text.includes('basicconfigurator')) return true;
    if (text.includes('appendermodelhandler') || text.includes('levelchangepropagator')) return true;
    if (text.includes('setting level of logger') || text.includes('propagating ')) return true;
    if (text.includes('could not find resource [logback')) return true;
    if (text.includes('this is logback-classic version')) return true;
    return false;
  }

  function selectRunFailureSummary(compileErrorMessage, compileStderr, compileStdout, maxChars) {
    const priorityPatterns = [
      /failed to initialize jpa entitymanagerfactory/i,
      /beancreationexception/i,
      /exception encountered during context initialization/i,
      /table \[[a-z0-9_]+\] contains physical column name/i,
      /application run failed/i,
      /error starting applicationcontext/i,
      /caused by:/i,
      /\[error\]/i,
      /compilation error/i,
      /cannot find symbol/i,
      /incompatible types/i,
      /illegal character/i,
      /failed to execute goal .*spring-boot-maven-plugin.*run/i,
    ];

    const orderedLines = [
      ...splitLines(compileStdout),
      ...splitLines(compileStderr),
      ...splitLines(compileErrorMessage),
    ];

    const preferred = [];
    for (const line of orderedLines) {
      if (isLogbackNoiseLine(line)) continue;
      if (priorityPatterns.some((pattern) => pattern.test(line))) {
        preferred.push(line);
      }
    }

    const withErrors = orderedLines.filter((line) => {
      if (isLogbackNoiseLine(line)) return false;
      const text = line.toLowerCase();
      return text.includes(' error ') || text.includes('exception');
    });

    const fallback = orderedLines.filter((line) => !isLogbackNoiseLine(line));
    const merged = Array.from(new Set([
      ...preferred,
      ...withErrors,
      ...splitLines(compileErrorMessage),
      ...fallback.slice(-8),
    ]));

    return pickErrorSummary(merged, maxChars);
  }

  function collectRelevantPaths(errorText, generatedFiles, explicitPaths = []) {
    const found = new Set();

    const unixMatches = errorText.match(/backend\/[A-Za-z0-9_./-]+/g) || [];
    for (const raw of unixMatches) {
      found.add(String(raw).replace(/,+$/, '').trim());
    }

    const windowsMatches = errorText.match(/backend\\[A-Za-z0-9_.\\-]+/g) || [];
    for (const raw of windowsMatches) {
      found.add(String(raw).replace(/,+$/, '').replace(/\\/g, '/').trim());
    }

    const generatedPathSet = new Set(
      (Array.isArray(generatedFiles) ? generatedFiles : [])
        .map((file) => String(file?.path || '').trim())
        .filter(Boolean),
    );

    for (const rawPath of explicitPaths) {
      const normalized = String(rawPath || '').trim().replace(/\\/g, '/');
      if (!normalized) continue;
      found.add(normalized);
    }

    const tableMatches = Array.from(
      String(errorText || '').matchAll(/table\s*\[([a-z0-9_]+)\]/gi),
      (match) => String(match[1] || '').toLowerCase(),
    );
    const hasJpaTableColumnMismatchSignal = /contains physical column name/i.test(String(errorText || ''));
    const blockedColumnTokens = new Set(['error', 'help', 'warning', 'warn', 'info', 'line', 'column', 'table']);
    const columnMatches = hasJpaTableColumnMismatchSignal
      ? Array.from(
        String(errorText || '').matchAll(/\[([a-z0-9_]+)\]/gi),
        (match) => String(match[1] || '').toLowerCase(),
      ).filter((token) => token && !blockedColumnTokens.has(token))
      : [];

    if (tableMatches.length || columnMatches.length) {
      for (const file of (Array.isArray(generatedFiles) ? generatedFiles : [])) {
        const path = String(file?.path || '').trim();
        const content = String(file?.content || '').toLowerCase();
        if (!path || !generatedPathSet.has(path)) continue;
        if (!path.includes('/src/main/')) continue;
        if (!content) continue;

        const tableHit = tableMatches.some((tableName) => tableName && content.includes(tableName));
        const columnHit = columnMatches.some((columnName) => {
          if (!columnName) return false;
          if (columnName.length < 3) return false;
          if (content.includes(columnName)) return true;
          const camelCase = columnName.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
          return camelCase !== columnName && content.includes(camelCase.toLowerCase());
        });

        if (tableHit || columnHit) {
          found.add(path);
        }
      }
    }

    return Array.from(found).filter((path) => generatedPathSet.has(path));
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];

    const compileErrorMessage = toText(json.compileErrorMessage);
    const compileStderr = toText(json.compileStderr);
    const compileStdout = toText(json.compileStdout);
    const compileFixNoChangeCount = Math.max(0, Number(json.compileFixNoChangeCount || 0));
    const compileFixAttempt = Number(json.compileFixAttempt || 0) + 1;
    const maxCompileFixAttempts = Math.max(1, Number(json.maxCompileFixAttempts || 50));
    const compileFixCanContinue = compileFixAttempt <= maxCompileFixAttempts;
    const compileValidationStage = String(json.compileValidationStage || 'compile').trim();
    const compileCommand = String(json.compileCommand || '').trim();
    const combinedErrorText = compileValidationStage === 'run'
      ? selectRunFailureSummary(compileErrorMessage, compileStderr, compileStdout, 12000)
      : pickErrorSummary([compileErrorMessage, compileStderr, compileStdout], 12000);
    const testFailedFilePaths = normalizePathArray(json.testFailedFilePaths);
    const testTargetFilePaths = normalizePathArray(json.testTargetFilePaths);
    const compileFixAppliedPaths = normalizePathArray(json.compileFixAppliedPaths);
    const compileFixParsedPaths = normalizePathArray(
      Array.isArray(json.compileFixParsedPaths)
        ? json.compileFixParsedPaths
        : (Array.isArray(json.compileFixFiles) ? json.compileFixFiles.map((file) => file?.path) : []),
    );
    const previousAttemptNumber = Math.max(0, Number(json.compileFixAttempt || 0));
    const previousModelResponse = compactText(json.compileFixRawResponse, 2400);
    let compileFixRecentModelResponses = normalizeRecentModelResponses(json.compileFixRecentModelResponses);
    if (previousAttemptNumber > 0 && previousModelResponse) {
      compileFixRecentModelResponses = compileFixRecentModelResponses
        .filter((entry) => Number(entry?.attempt || 0) !== previousAttemptNumber);
      compileFixRecentModelResponses.push({
        attempt: previousAttemptNumber,
        parseError: toText(json.compileFixParseError),
        parsedPaths: compileFixParsedPaths.slice(0, 20),
        appliedPaths: compileFixAppliedPaths.slice(0, 20),
        response: previousModelResponse,
      });
      compileFixRecentModelResponses = compileFixRecentModelResponses.slice(-MAX_RECENT_MODEL_RESPONSES);
    }
    const currentErrorSignature = buildErrorSignature(combinedErrorText);
    const currentErrorBucket = buildErrorBucket(combinedErrorText);
    const firstCompilerErrors = extractCompilerErrorLines(combinedErrorText, MAX_FIRST_COMPILER_ERRORS);
    const compilerErrorLineCount = countCompilerErrorLines(combinedErrorText);
    const previousHistory = Array.isArray(json.compileFixHistory) ? json.compileFixHistory : [];
    const previousErrorSignature = String(
      json.lastCompileErrorSignature ||
      previousHistory[previousHistory.length - 1]?.errorSignature ||
      ''
    ).trim();
    const recentHistory = previousHistory.slice(-4);
    const recentBucketMatches = currentErrorBucket
      ? recentHistory.filter((entry) => String(entry?.errorBucket || '').trim() === currentErrorBucket).length
      : 0;
    const isRepeatedError = Boolean(
      currentErrorSignature &&
      previousErrorSignature &&
      currentErrorSignature === previousErrorSignature
    ) || recentBucketMatches >= 2;
    const errorBucketRepeatCount = currentErrorBucket ? recentBucketMatches + 1 : 0;
    const recentSameBucketEntries = currentErrorBucket
      ? previousHistory
        .filter((entry) => String(entry?.errorBucket || '').trim() === currentErrorBucket)
        .slice(-(STAGNATION_WINDOW - 1))
      : [];
    const recentErrorCounts = [
      ...recentSameBucketEntries.map((entry) => Math.max(0, Number(entry?.errorLineCount || 0))),
      compilerErrorLineCount,
    ].slice(-STAGNATION_WINDOW);
    const stagnationByBucket = Boolean(
      currentErrorBucket
      && errorBucketRepeatCount >= STAGNATION_WINDOW
      && recentErrorCounts.length >= STAGNATION_WINDOW
      && hasNonDecreasingTrend(recentErrorCounts)
    );
    const repeatedBucketForWideRecovery = Boolean(
      currentErrorBucket && errorBucketRepeatCount >= WIDE_RECOVERY_BUCKET_THRESHOLD
    );
    const repeatedNoChangeForWideRecovery = compileFixNoChangeCount >= WIDE_RECOVERY_NO_CHANGE_THRESHOLD;
    let compileFixWideRecoveryTurnsLeft = Math.max(0, Number(json.compileFixWideRecoveryTurnsLeft || 0));
    if (repeatedBucketForWideRecovery || repeatedNoChangeForWideRecovery) {
      compileFixWideRecoveryTurnsLeft = WIDE_RECOVERY_ITERATIONS;
    } else if (compileFixWideRecoveryTurnsLeft > 0) {
      compileFixWideRecoveryTurnsLeft -= 1;
    }
    const compileFixUseWideRecoveryMode = compileFixWideRecoveryTurnsLeft > 0;
    const compileFixUseSurgicalMode = Boolean(
      !compileFixUseWideRecoveryMode && (stagnationByBucket || compileFixNoChangeCount >= 2)
    );
    const compileFixIsStuck = Boolean(currentErrorBucket && errorBucketRepeatCount >= 3)
      || compileFixUseSurgicalMode
      || compileFixUseWideRecoveryMode;
    const compileFixStuckReason = compileFixIsStuck
      ? (
        compileFixUseWideRecoveryMode
          ? (
            repeatedBucketForWideRecovery
              ? `Wide recovery mode enabled: bucket "${currentErrorBucket}" repeated ${errorBucketRepeatCount} attempts.`
              : `Wide recovery mode enabled after ${compileFixNoChangeCount} no-change attempts.`
          )
          : compileFixUseSurgicalMode
          ? `Stagnation detected for bucket "${currentErrorBucket}" with non-decreasing error volume (${recentErrorCounts.join(' -> ')}).`
          : `Repeated error bucket "${currentErrorBucket}" for ${errorBucketRepeatCount} consecutive attempts.`
      )
      : '';
    const compileFixForceConcreteEdits = Boolean(
      compileFixNoChangeCount >= 1 || (previousAttemptNumber > 0 && compileFixAppliedPaths.length === 0)
    );
    const pomTouchedLastAttempt = compileFixAppliedPaths.includes('backend/pom.xml');
    const recentPomTouchCount = previousHistory
      .slice(-5)
      .filter((entry) => Boolean(entry?.pomTouched))
      .length + (pomTouchedLastAttempt ? 1 : 0);

    let compileFixStopReason = '';
    if (compileFixAttempt > maxCompileFixAttempts) {
      compileFixStopReason = `Reached max compile-fix attempts (${maxCompileFixAttempts}).`;
    }

    const relevantErrorPaths = collectRelevantPaths(
      combinedErrorText,
      generatedFiles,
      [...testFailedFilePaths, ...testTargetFilePaths],
    );
    const firstCompilerErrorPaths = collectRelevantPaths(
      firstCompilerErrors.join('\n'),
      generatedFiles,
      [...testFailedFilePaths, ...testTargetFilePaths],
    );
    if (
      isDependencyLikeBucket(currentErrorBucket)
      && generatedFiles.some((file) => String(file?.path || '').trim() === 'backend/pom.xml')
      && !firstCompilerErrorPaths.includes('backend/pom.xml')
    ) {
      firstCompilerErrorPaths.unshift('backend/pom.xml');
    }
    const currentConvergenceScore = computeConvergenceScore({
      compilePassed: Boolean(json.compilePassed),
      errorBucket: currentErrorBucket,
      validationStage: compileValidationStage,
      errorLineCount: compilerErrorLineCount,
      noChangeCount: compileFixNoChangeCount,
    });
    const compileFixRollbackToBest = false;

    const compileFixHistory = [
      ...previousHistory,
      {
        attempt: compileFixAttempt,
        compilePassed: Boolean(json.compilePassed),
        compileExitCode: json.compileExitCode,
        compileRawExitCode: json.compileRawExitCode,
        compileValidationStage,
        compileCommand,
        isRepeatedError,
        failedTestFileCount: testFailedFilePaths.length,
        testTargetFileCount: testTargetFilePaths.length,
        summary: pickErrorSummary([compileErrorMessage, compileStderr], 1500),
        errorSignature: currentErrorSignature,
        errorBucket: currentErrorBucket,
        errorLineCount: compilerErrorLineCount,
        convergenceScore: currentConvergenceScore,
        errorBucketRepeatCount,
        compileFixIsStuck,
        compileFixUseSurgicalMode,
        compileFixUseWideRecoveryMode,
        compileFixWideRecoveryTurnsLeft,
        compileFixRollbackToBest,
        pomTouched: pomTouchedLastAttempt,
      },
    ];

    return {
      json: {
        ...json,
        generatedFiles,
        generatedFilePaths: generatedFiles.map((file) => String(file?.path || '').trim()).filter(Boolean),
        generatedFileCountTotal: generatedFiles.length,
        allPlannedFiles: generatedFiles.map((file) => ({ path: String(file?.path || '').trim() })).filter((file) => file.path),
        compileFixAttempt,
        maxCompileFixAttempts,
        compileFixCanContinue,
        compileFixShouldStop: !compileFixCanContinue,
        compileFixStopReason,
        compileValidationStage,
        compileCommand,
        compileErrorContext: combinedErrorText,
        compileErrorSignature: currentErrorSignature,
        compileErrorBucket: currentErrorBucket,
        compilerErrorLineCount,
        firstCompilerErrors,
        firstCompilerErrorPaths,
        currentConvergenceScore,
        errorBucketRepeatCount,
        lastCompileErrorSignature: currentErrorSignature,
        isRepeatedError,
        compileFixIsStuck,
        compileFixUseSurgicalMode,
        compileFixUseWideRecoveryMode,
        compileFixWideRecoveryTurnsLeft,
        compileFixStuckReason,
        compileFixForceConcreteEdits,
        compileFixRecentModelResponses,
        recentPomTouchCount,
        compileFixWorseStreak: 0,
        compileFixRollbackToBest,
        compileFixRollbackReason: '',
        compileFixBestState: null,
        relevantErrorPaths,
        testFailedFilePaths,
        testTargetFilePaths,
        compileFixHistory,
      },
      binary: item.binary ?? {},
    };
  });
}

return bePrepareCompileFixState();

async function beCompileGeneratedBackend() {
  const item = $input.first();
  if (!item) {
    return [{
      json: {
        compilePassed: false,
        compileErrorMessage: 'No backend generation state available for compilation.',
        compileExitCode: 1,
        compileRawExitCode: 'NO_INPUT',
        compileHadError: true,
      },
      binary: {},
    }];
  }

  const json = item.json || {};
  const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
  if (!generatedFiles.length) {
    return [{
      json: {
        ...json,
        compilePassed: false,
        compileErrorMessage: 'No generated backend files found for compilation.',
        compileExitCode: 1,
        compileRawExitCode: 'NO_GENERATED_FILES',
        compileHadError: true,
      },
      binary: item.binary ?? {},
    }];
  }

  let fs;
  let path;
  let os;
  let childProcess;
  try {
    fs = require('fs');
    path = require('path');
    os = require('os');
    childProcess = require('child_process');
  } catch (error) {
    return [{
      json: {
        ...json,
        compilePassed: false,
        compileErrorMessage:
          'Compilation step requires built-in modules (fs, path, os, child_process). ' +
          'If disabled, set NODE_FUNCTION_ALLOW_BUILTIN=fs,path,os,child_process. ' +
          String(error?.message ?? error ?? ''),
        compileExitCode: 1,
        compileRawExitCode: 'MISSING_BUILTINS',
        compileHadError: true,
      },
      binary: item.binary ?? {},
    }];
  }

  function normalizeContent(contentValue) {
    if (typeof contentValue === 'string') return contentValue;
    if (contentValue === null || contentValue === undefined) return '';
    if (typeof contentValue === 'object') return JSON.stringify(contentValue, null, 2);
    return String(contentValue);
  }

  function buildGeneratedIndexes(files) {
    const generatedContentByPath = new Map();
    const generatedPathSet = new Set();
    const basenameIndex = new Map();

    for (const file of files) {
      const filePath = String(file?.path || '').trim().replace(/\\/g, '/');
      if (!filePath.startsWith('backend/')) continue;
      if (filePath === 'backend/target' || filePath.startsWith('backend/target/')) continue;

      const content = normalizeContent(file?.content);
      generatedContentByPath.set(filePath, content);
      generatedPathSet.add(filePath);

      const basename = filePath.split('/').pop()?.toLowerCase() || '';
      if (!basename) continue;
      if (!basenameIndex.has(basename)) basenameIndex.set(basename, []);
      basenameIndex.get(basename).push(filePath);
    }

    return { generatedContentByPath, generatedPathSet, basenameIndex };
  }

  function extractTopLevelTypeDeclarations(content) {
    const text = String(content || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
    const declarations = [];
    const pattern = /^\s*(public\s+)?(?:abstract\s+|final\s+)?(?:class|interface|enum|record)\s+([A-Za-z_][A-Za-z0-9_]*)\b/gm;
    for (const match of text.matchAll(pattern)) {
      declarations.push({
        isPublic: Boolean(match[1]),
        typeName: String(match[2] || '').trim(),
      });
    }
    return declarations.filter((entry) => entry.typeName);
  }

  function runPreCompileGuards(generatedContentByPath) {
    const typeToPaths = new Map();
    const violations = [];

    for (const [filePath, content] of generatedContentByPath.entries()) {
      if (!/\.java$/i.test(filePath)) continue;
      const declarations = extractTopLevelTypeDeclarations(content);
      const basename = filePath.split('/').pop() || '';
      const fileStem = basename.replace(/\.java$/i, '');

      for (const declaration of declarations) {
        if (!typeToPaths.has(declaration.typeName)) typeToPaths.set(declaration.typeName, []);
        typeToPaths.get(declaration.typeName).push(filePath);

        if (declaration.isPublic && declaration.typeName && declaration.typeName !== fileStem) {
          violations.push(
            `[ERROR] ${filePath}: public type "${declaration.typeName}" must be declared in ${declaration.typeName}.java`,
          );
        }
      }

      const hasSuspiciousEscapedQuotes =
        /@\w+[^\n]*\\\"/.test(content)
        || /\b(name|value|path|strategy)\s*=\s*\\\"/.test(content)
        || /new\s+[A-Za-z_][A-Za-z0-9_<>]*\([^)]*\\\"/.test(content)
        || /return\s+[^;\n]*\\\"/.test(content);
      if (hasSuspiciousEscapedQuotes) {
        violations.push(
          `[ERROR] ${filePath}: suspicious escaped quote sequence (\\\") detected in Java source.`,
        );
      }
    }

    for (const [typeName, paths] of typeToPaths.entries()) {
      const uniquePaths = Array.from(new Set(paths)).sort((a, b) => a.localeCompare(b));
      if (uniquePaths.length <= 1) continue;
      violations.push(
        `[ERROR] duplicate class: ${typeName} declared in ${uniquePaths.join(', ')}`,
      );
    }

    return Array.from(new Set(violations));
  }

  function normalizeClassName(value) {
    return String(value || '')
      .trim()
      .replace(/[:;,]+$/, '')
      .replace(/\$.*$/, '');
  }

  function classToPathCandidates(className, preferTests = false) {
    const cleanClass = normalizeClassName(className);
    if (!cleanClass) return [];

    const parts = cleanClass.split('.').filter(Boolean);
    if (!parts.length) return [];

    const classLeaf = parts[parts.length - 1];
    const packagePath = parts.slice(0, -1).join('/');
    const exts = ['java', 'kt', 'groovy'];

    const testRoots = [
      'backend/src/test/java',
      'backend/src/test/kotlin',
      'backend/src/test/groovy',
    ];
    const mainRoots = [
      'backend/src/main/java',
      'backend/src/main/kotlin',
      'backend/src/main/groovy',
    ];
    const roots = preferTests ? [...testRoots, ...mainRoots] : [...mainRoots, ...testRoots];

    const candidates = [];
    for (const root of roots) {
      for (const ext of exts) {
        if (packagePath) {
          candidates.push(`${root}/${packagePath}/${classLeaf}.${ext}`);
        } else {
          candidates.push(`${root}/${classLeaf}.${ext}`);
        }
      }
    }
    return candidates;
  }

  function collectFailingTestClassNames(outputText) {
    const text = String(outputText || '');
    const found = new Set();
    const patterns = [
      /\[ERROR\]\s+([A-Za-z_][A-Za-z0-9_.$]*)\.[A-Za-z_][A-Za-z0-9_$<>]*\s+.*<<<\s+(?:FAILURE|ERROR)!/g,
      /\[ERROR\]\s+([A-Za-z_][A-Za-z0-9_.$]*Test[A-Za-z0-9_$]*)\s+Time elapsed.*<<<\s+(?:FAILURE|ERROR)!/g,
      /\[ERROR\]\s+([A-Za-z_][A-Za-z0-9_.$]*Test[A-Za-z0-9_$]*)\.[A-Za-z_][A-Za-z0-9_$<>]*:\d+/g,
      /\bin\s+([A-Za-z_][A-Za-z0-9_.$]*Test[A-Za-z0-9_$]*)\b/g,
      /\bat\s+([A-Za-z_][A-Za-z0-9_.$]*Test[A-Za-z0-9_$]*)\.[A-Za-z_][A-Za-z0-9_$<>]*\(/g,
    ];

    for (const pattern of patterns) {
      for (const match of text.matchAll(pattern)) {
        const className = normalizeClassName(match[1]);
        if (!className) continue;
        if (!/Test/i.test(className)) continue;
        found.add(className);
      }
    }

    return Array.from(found);
  }

  function resolveFailingTestFilePaths(outputText, generatedPathSet, basenameIndex) {
    const text = String(outputText || '');
    const testPaths = new Set();

    const explicitPathPattern = /backend[\\/](?:src[\\/](?:test|it)[\\/][A-Za-z0-9_.\\/\\-]+\.(?:java|kt|groovy))/g;
    for (const match of text.matchAll(explicitPathPattern)) {
      const normalized = String(match[1] || match[0]).replace(/\\/g, '/').trim();
      if (generatedPathSet.has(normalized)) {
        testPaths.add(normalized);
      }
    }

    for (const className of collectFailingTestClassNames(text)) {
      const candidates = classToPathCandidates(className, true);
      for (const candidate of candidates) {
        if (generatedPathSet.has(candidate) && candidate.includes('/src/test/')) {
          testPaths.add(candidate);
          break;
        }
      }

      const leaf = className.split('.').pop() || '';
      if (!leaf) continue;
      const basename = `${leaf}.java`.toLowerCase();
      const options = basenameIndex.get(basename) || [];
      for (const option of options) {
        if (option.includes('/src/test/')) {
          testPaths.add(option);
        }
      }
    }

    return Array.from(testPaths).sort((a, b) => a.localeCompare(b));
  }

  function collectSourceCandidatesFromLog(outputText, generatedPathSet, basenameIndex) {
    const text = String(outputText || '');
    const sourcePaths = new Set();

    const stackClassPattern = /\bat\s+([A-Za-z_][A-Za-z0-9_.$]+)\.[A-Za-z_][A-Za-z0-9_$<>]*\([^)]+\)/g;
    for (const match of text.matchAll(stackClassPattern)) {
      const className = normalizeClassName(match[1]);
      if (!className || /Test/i.test(className)) continue;
      const candidates = classToPathCandidates(className, false);
      for (const candidate of candidates) {
        if (generatedPathSet.has(candidate) && candidate.includes('/src/main/')) {
          sourcePaths.add(candidate);
          break;
        }
      }
    }

    const javaFilePattern = /\(([A-Za-z0-9_.$-]+\.java):\d+\)/g;
    for (const match of text.matchAll(javaFilePattern)) {
      const basename = String(match[1] || '').toLowerCase();
      if (!basename || basename.endsWith('test.java')) continue;
      const options = basenameIndex.get(basename) || [];
      for (const option of options) {
        if (option.includes('/src/main/')) {
          sourcePaths.add(option);
        }
      }
    }

    return sourcePaths;
  }

  function inferSourceCandidatesFromTestFiles(testFilePaths, generatedContentByPath, generatedPathSet, basenameIndex) {
    const sourcePaths = new Set();
    const blockedPrefixes = [
      'java.',
      'javax.',
      'jakarta.',
      'org.junit.',
      'org.mockito.',
      'org.assertj.',
      'org.hamcrest.',
      'org.springframework.',
      'lombok.',
      'com.fasterxml.',
      'org.apache.',
    ];

    for (const testPath of testFilePaths) {
      const content = String(generatedContentByPath.get(testPath) || '');
      if (!content) continue;

      const importPattern = /^\s*import\s+([A-Za-z_][A-Za-z0-9_.]+)\s*;/gm;
      for (const match of content.matchAll(importPattern)) {
        const fqcn = String(match[1] || '').trim();
        if (!fqcn || blockedPrefixes.some((prefix) => fqcn.startsWith(prefix))) continue;
        const candidates = classToPathCandidates(fqcn, false);
        for (const candidate of candidates) {
          if (generatedPathSet.has(candidate) && candidate.includes('/src/main/')) {
            sourcePaths.add(candidate);
            break;
          }
        }
      }

      const classLiteralPattern = /\b([A-Z][A-Za-z0-9_]*)\.class\b/g;
      for (const match of content.matchAll(classLiteralPattern)) {
        const classBase = String(match[1] || '').trim();
        if (!classBase || /Test$/i.test(classBase)) continue;
        const basename = `${classBase}.java`.toLowerCase();
        const options = basenameIndex.get(basename) || [];
        for (const option of options) {
          if (option.includes('/src/main/')) {
            sourcePaths.add(option);
          }
        }
      }

      const testBasename = testPath.split('/').pop()?.replace(/\.(java|kt|groovy)$/i, '') || '';
      if (testBasename) {
        const fromTestName = testBasename.replace(/(IT|Tests?|TestCase)$/i, '');
        if (fromTestName && fromTestName !== testBasename) {
          const basename = `${fromTestName}.java`.toLowerCase();
          const options = basenameIndex.get(basename) || [];
          for (const option of options) {
            if (option.includes('/src/main/')) {
              sourcePaths.add(option);
            }
          }
        }
      }
    }

    return sourcePaths;
  }

    function ensureDirectoryPath(targetPath) {
    const resolved = path.resolve(targetPath);
    const root = path.parse(resolved).root;
    const segments = resolved.slice(root.length).split(path.sep).filter(Boolean);

    let current = root;
    for (const segment of segments) {
      current = path.join(current, segment);
      if (!fs.existsSync(current)) {
        fs.mkdirSync(current);
        continue;
      }

      let stat;
      try {
        stat = fs.statSync(current);
      } catch {
        fs.rmSync(current, { force: true });
        fs.mkdirSync(current);
        continue;
      }

      if (!stat.isDirectory()) {
        fs.rmSync(current, { force: true });
        fs.mkdirSync(current);
      }
    }
  }
  const compileSessionId = String(json.compileSessionId || `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
  const workspaceRoot = path.join(os.tmpdir(), 'n8n-backend-build', compileSessionId);
  const backendDir = path.join(workspaceRoot, 'backend');
  const generatedIndexes = buildGeneratedIndexes(generatedFiles);
  const { generatedContentByPath, generatedPathSet, basenameIndex } = generatedIndexes;
  if (!generatedContentByPath.size) {
    return [{
      json: {
        ...json,
        compileSessionId,
        compileWorkspace: backendDir,
        compilePassed: false,
        compileErrorMessage: 'No materializable backend source files found (backend/target entries are ignored).',
        compileExitCode: 1,
        compileRawExitCode: 'NO_MATERIALIZABLE_FILES',
        compileHadError: true,
      },
      binary: item.binary ?? {},
    }];
  }

  const preCompileGuardViolations = runPreCompileGuards(generatedContentByPath);
  if (preCompileGuardViolations.length > 0) {
    const guardLog = [
      '[ERROR] PRE_COMPILE_GUARD_FAILED',
      ...preCompileGuardViolations.slice(0, 40),
    ].join('\n');
    return [{
      json: {
        ...json,
        compileSessionId,
        compileWorkspace: backendDir,
        compileCommand: 'pre-compile-guard',
        compileValidationStage: 'guard',
        compilePassed: false,
        compileExitCode: 1,
        compileRawExitCode: 'PRE_COMPILE_GUARD_FAILED',
        compileHadError: true,
        compileStdout: '',
        compileStderr: guardLog,
        compileErrorMessage: guardLog,
        preCompileGuardFailed: true,
        preCompileGuardViolationCount: preCompileGuardViolations.length,
        preCompileGuardViolations: preCompileGuardViolations.slice(0, 40),
      },
      binary: item.binary ?? {},
    }];
  }

  try {
    if (fs.existsSync(backendDir)) {
      fs.rmSync(backendDir, { recursive: true, force: true });
    }
    fs.mkdirSync(backendDir, { recursive: true });

    for (const [filePath, content] of generatedContentByPath.entries()) {
      const absolutePath = path.join(workspaceRoot, ...filePath.split('/'));
      ensureDirectoryPath(path.dirname(absolutePath));
      fs.writeFileSync(absolutePath, content, 'utf8');
    }

    const targetDir = path.join(backendDir, 'target');
    if (fs.existsSync(targetDir)) {
      fs.rmSync(targetDir, { recursive: true, force: true });
    }
  } catch (error) {
    return [{
      json: {
        ...json,
        compileSessionId,
        compileWorkspace: backendDir,
        compilePassed: false,
        compileErrorMessage: 'Failed to materialize backend directory before compile: ' + String(error?.message ?? error ?? ''),
        compileExitCode: 1,
        compileRawExitCode: 'MATERIALIZE_FAILED',
        compileHadError: true,
      },
      binary: item.binary ?? {},
    }];
  }

  if (!fs.existsSync(path.join(backendDir, 'pom.xml'))) {
    return [{
      json: {
        ...json,
        compileSessionId,
        compileWorkspace: backendDir,
        compilePassed: false,
        compileErrorMessage: 'Generated backend does not contain backend/pom.xml, cannot run Maven compile.',
        compileExitCode: 1,
        compileRawExitCode: 'MISSING_POM',
        compileHadError: true,
      },
      binary: item.binary ?? {},
    }];
  }

  const MAX_OUTPUT_CHARS = 20 * 1024 * 1024;
  const SPRING_BOOT_STARTUP_TIMEOUT_MS = Math.max(30000, Number(json.springBootStartupTimeoutMs || 120000));
  const MAVEN_TEST_TIMEOUT_MS = Math.max(60000, Number(json.mavenTestTimeoutMs || 300000));
  const forceDependencyUpdate = json.forceDependencyUpdate !== false;
  const compileArgs = forceDependencyUpdate
    ? ['-q', '-U', '-DskipTests', 'compile']
    : ['-q', '-DskipTests', 'compile'];
  const compileCommandText = `mvn ${compileArgs.join(' ')}`;
  const runArgs = [
    '-q',
    '-DskipTests',
    '-Dmaven.test.skip=true',
    '-Dspring-boot.run.useTestClasspath=false',
    'spring-boot:run',
  ];
  const runCommandText = `mvn ${runArgs.join(' ')}`;

  function appendLimited(target, chunk) {
    const value = String(chunk ?? '');
    if (!value) return target;
    const next = target + value;
    if (next.length <= MAX_OUTPUT_CHARS) return next;
    return next.slice(next.length - MAX_OUTPUT_CHARS);
  }

  function runMavenCompile() {
    return new Promise((resolve) => {
      childProcess.execFile(
        'mvn',
        compileArgs,
        {
          cwd: backendDir,
          windowsHide: true,
          maxBuffer: MAX_OUTPUT_CHARS,
        },
        (error, stdout, stderr) => {
          const hadError = Boolean(error);
          const rawCode = error?.code;
          const normalizedCode = typeof rawCode === 'number' ? rawCode : (hadError ? 1 : 0);
          resolve({
            code: normalizedCode,
            rawCode: rawCode == null ? '' : String(rawCode),
            hadError,
            stdout: String(stdout ?? ''),
            stderr: String(stderr ?? ''),
            errorMessage: String(error?.message ?? ''),
          });
        },
      );
    });
  }

  function runSpringBootValidation() {
    return new Promise((resolve) => {
      const startupPattern = /Started\s+.+\s+in\s+[0-9.]+\s+seconds/i;
      let stdout = '';
      let stderr = '';
      let started = false;
      let timedOut = false;
      let finished = false;
      let spawnErrorMessage = '';

      const child = childProcess.spawn(
        'mvn',
        runArgs,
        {
          cwd: backendDir,
          windowsHide: true,
        },
      );

      function finalize(payload) {
        if (finished) return;
        finished = true;
        clearTimeout(timer);
        resolve({
          ...payload,
          stdout,
          stderr,
        });
      }

      function tryMarkStarted() {
        if (started) return;
        const combined = stdout + '\n' + stderr;
        if (!startupPattern.test(combined)) return;
        started = true;
        setTimeout(() => {
          try {
            child.kill('SIGTERM');
          } catch {}
        }, 500);
        setTimeout(() => {
          try {
            child.kill('SIGKILL');
          } catch {}
        }, 3000);
      }

      const timer = setTimeout(() => {
        timedOut = true;
        try {
          child.kill('SIGTERM');
        } catch {}
        setTimeout(() => {
          try {
            child.kill('SIGKILL');
          } catch {}
        }, 2500);
      }, SPRING_BOOT_STARTUP_TIMEOUT_MS);

      child.stdout.on('data', (chunk) => {
        stdout = appendLimited(stdout, chunk);
        tryMarkStarted();
      });

      child.stderr.on('data', (chunk) => {
        stderr = appendLimited(stderr, chunk);
        tryMarkStarted();
      });

      child.on('error', (error) => {
        spawnErrorMessage = String(error?.message ?? error ?? '');
      });

      child.on('close', (exitCode, signal) => {
        if (started) {
          finalize({
            code: 0,
            rawCode: signal ? String(signal) : String(exitCode ?? ''),
            hadError: false,
            errorMessage: '',
            started: true,
            timedOut: false,
          });
          return;
        }

        if (timedOut) {
          finalize({
            code: 1,
            rawCode: 'RUN_STARTUP_TIMEOUT',
            hadError: true,
            errorMessage: `spring-boot:run did not report successful startup within ${SPRING_BOOT_STARTUP_TIMEOUT_MS}ms.`,
            started: false,
            timedOut: true,
          });
          return;
        }

        const normalizedCode = typeof exitCode === 'number' ? exitCode : 1;
        finalize({
          code: normalizedCode,
          rawCode: signal ? String(signal) : String(exitCode ?? ''),
          hadError: true,
          errorMessage: spawnErrorMessage || `spring-boot:run exited before successful startup (code=${normalizedCode}).`,
          started: false,
          timedOut: false,
        });
      });
    });
  }

  function runMavenTests() {
    return new Promise((resolve) => {
      childProcess.execFile(
        'mvn',
        ['-q', 'test'],
        {
          cwd: backendDir,
          windowsHide: true,
          timeout: MAVEN_TEST_TIMEOUT_MS,
          maxBuffer: MAX_OUTPUT_CHARS,
        },
        (error, stdout, stderr) => {
          const hadError = Boolean(error);
          const rawCode = error?.code;
          const normalizedCode = typeof rawCode === 'number' ? rawCode : (hadError ? 1 : 0);
          resolve({
            code: normalizedCode,
            rawCode: rawCode == null ? '' : String(rawCode),
            hadError,
            stdout: String(stdout ?? ''),
            stderr: String(stderr ?? ''),
            errorMessage: String(error?.message ?? ''),
          });
        },
      );
    });
  }

  function extractTestFailureContext(testResult) {
    const combined = [testResult.errorMessage, testResult.stderr, testResult.stdout]
      .filter(Boolean)
      .join('\n');

    const failingTestFiles = resolveFailingTestFilePaths(combined, generatedPathSet, basenameIndex);
    const sourceCandidates = collectSourceCandidatesFromLog(combined, generatedPathSet, basenameIndex);
    const sourceFromTests = inferSourceCandidatesFromTestFiles(
      failingTestFiles,
      generatedContentByPath,
      generatedPathSet,
      basenameIndex,
    );

    const targetSourceFiles = Array.from(new Set([
      ...sourceCandidates,
      ...sourceFromTests,
    ]))
      .filter((filePath) => filePath.includes('/src/main/'))
      .sort((a, b) => a.localeCompare(b));

    return {
      testFailedFilePaths: failingTestFiles,
      testTargetFilePaths: targetSourceFiles,
    };
  }

  const compileResult = await runMavenCompile();

  if (compileResult.code !== 0 || compileResult.hadError) {
    return [{
      json: {
        ...json,
        compileSessionId,
        compileCommand: compileCommandText,
        compileWorkspace: backendDir,
        compileValidationStage: 'compile',
        compileExitCode: compileResult.code,
        compileRawExitCode: compileResult.rawCode,
        compileHadError: compileResult.hadError,
        compileStdout: compileResult.stdout,
        compileStderr: compileResult.stderr,
        compileErrorMessage: compileResult.errorMessage,
        compilePassed: false,
      },
      binary: item.binary ?? {},
    }];
  }

  const runResult = await runSpringBootValidation();

  if (runResult.code !== 0 || runResult.hadError || !runResult.started) {
    return [{
      json: {
        ...json,
        compileSessionId,
        compileCommand: runCommandText,
        compileWorkspace: backendDir,
        compileValidationStage: 'run',
        compileExitCode: runResult.code,
        compileRawExitCode: runResult.rawCode,
        compileHadError: runResult.hadError,
        compileStdout: runResult.stdout,
        compileStderr: runResult.stderr,
        compileErrorMessage: runResult.errorMessage,
        compilePassed: false,
      },
      binary: item.binary ?? {},
    }];
  }

  const testResult = await runMavenTests();

  if (testResult.code !== 0 || testResult.hadError) {
    const testFailureContext = extractTestFailureContext(testResult);
    return [{
      json: {
        ...json,
        ...testFailureContext,
        compileSessionId,
        compileCommand: 'mvn -q test',
        compileWorkspace: backendDir,
        compileValidationStage: 'test',
        compileExitCode: testResult.code,
        compileRawExitCode: testResult.rawCode,
        compileHadError: testResult.hadError,
        compileStdout: testResult.stdout,
        compileStderr: testResult.stderr,
        compileErrorMessage: testResult.errorMessage,
        compilePassed: false,
      },
      binary: item.binary ?? {},
    }];
  }

  return [{
    json: {
      ...json,
      testFailedFilePaths: [],
      testTargetFilePaths: [],
      compileSessionId,
      compileCommand: 'mvn -q test',
      compileWorkspace: backendDir,
      compileValidationStage: 'test',
      compileExitCode: 0,
      compileRawExitCode: testResult.rawCode,
      compileHadError: false,
      compileStdout: testResult.stdout,
      compileStderr: testResult.stderr,
      compileErrorMessage: '',
      compilePassed: true,
    },
    binary: item.binary ?? {},
  }];
}

return beCompileGeneratedBackend();

async function loadBackendZipForValidation() {
  const item = $input.first() || { json: {}, binary: {} };
  const json = item.json || {};
  const binary = item.binary || {};

  const maxFileBytes = 1024 * 1024 * 2;

  function normalizeBackendPath(rawPath) {
    const normalized = String(rawPath || '')
      .replace(/\\/g, '/')
      .trim()
      .replace(/^\.\//, '')
      .replace(/^\/+/, '')
      .replace(/\/+/g, '/');

    if (!normalized) return '';
    if (normalized.endsWith('/')) return '';
    if (normalized.startsWith('__MACOSX/')) return '';
    if (normalized.endsWith('/.DS_Store')) return '';
    if (normalized === '.DS_Store') return '';

    if (normalized.startsWith('backend/')) return normalized;
    if (normalized === 'backend') return '';

    return `backend/${normalized}`;
  }

  function isLikelyTextBuffer(buffer) {
    const len = Math.min(buffer.length, 2048);
    for (let index = 0; index < len; index += 1) {
      if (buffer[index] === 0) return false;
    }
    return true;
  }

  async function readBinaryBuffer(propertyName, binaryEntry) {
    try {
      if (typeof this?.helpers?.getBinaryDataBuffer === 'function') {
        const fromHelper = await this.helpers.getBinaryDataBuffer(0, propertyName);
        if (fromHelper) return fromHelper;
      }
    } catch {}

    try {
      const raw = String(binaryEntry?.data ?? '');
      if (!raw || raw === 'filesystem-v2') return null;
      return Buffer.from(raw, 'base64');
    } catch {
      return null;
    }
  }

  const extractedEntries = Object.entries(binary).filter(([propertyName]) => /^current_/i.test(propertyName));
  if (!extractedEntries.length) {
    return [{
      json: {
        ...json,
        compilePassed: false,
        compileErrorMessage: 'No extracted files found. Upload a valid backend ZIP in the form field backendZip.',
        compileExitCode: 1,
        compileRawExitCode: 'MISSING_ZIP_CONTENT',
        compileHadError: true,
        generatedFiles: [],
      },
      binary,
    }];
  }

  const byPath = new Map();

  for (const [propertyName, entry] of extractedEntries) {
    const rawEntryPath = (() => {
      const fileName = String(entry?.fileName || '').replace(/\\/g, '/').trim();
      const directory = String(entry?.directory || '').replace(/\\/g, '/').trim();

      if (!fileName) return '';
      if (!directory) return fileName;
      if (fileName.startsWith('backend/') || fileName.includes('/')) return fileName;

      return directory.replace(/\/+$/, '') + '/' + fileName.replace(/^\/+/, '');
    })();
    const filePath = normalizeBackendPath(rawEntryPath);
    if (!filePath) continue;

    const buffer = await readBinaryBuffer.call(this, propertyName, entry);
    if (!buffer) continue;
    if (buffer.length > maxFileBytes) continue;
    if (!isLikelyTextBuffer(buffer)) continue;

    const content = buffer.toString('utf8');
    if (!byPath.has(filePath)) {
      byPath.set(filePath, content);
    }
  }

  const generatedFiles = Array.from(byPath.entries())
    .map(([path, content]) => ({ path, content }))
    .sort((a, b) => a.path.localeCompare(b.path));

  if (!generatedFiles.length) {
    return [{
      json: {
        ...json,
        compilePassed: false,
        compileErrorMessage: 'Uploaded ZIP did not contain readable text files for backend validation.',
        compileExitCode: 1,
        compileRawExitCode: 'NO_TEXT_FILES',
        compileHadError: true,
        generatedFiles: [],
      },
      binary,
    }];
  }

  return [{
    json: {
      ...json,
      generatedFiles,
      generatedFilePaths: generatedFiles.map((file) => file.path),
      generatedFileCountTotal: generatedFiles.length,
      allPlannedFiles: generatedFiles.map((file) => ({ path: file.path })),
      compileFixAttempt: Number(json.compileFixAttempt || 0),
      maxCompileFixAttempts: Math.max(1, Number(json.maxCompileFixAttempts || 50)),
      requirementsText: String(json.requirementsText || ''),
      requirementsFile: String(json.requirementsFile || 'requirements.txt'),
      openapiText: String(json.openapiText || ''),
      openapiFile: String(json.openapiFile || 'openapi.yaml'),
    },
    binary,
  }];
}

return loadBackendZipForValidation();
